(یوسف/ ۶۴)

الصّادق (علیه السلام)-

لَمَّا فَقَدَ یَعْقُوبُ (علیه السلام) یُوسُفَ (علیه السلام) اشْتَدَّ حُزْنُهُ عَلَیْهِ وَ بُکَاؤُهُ حَتَّی ابْیَضَّتْ عَیْناهُ مِنَ الْحُزْنِ وَ احْتَاجَ حَاجَهًًْ شَدِیدَهًًْ وَ تَغَیَّرَتْ حَالُهُ قَالَ وَ کَانَ یَمْتَارُ الْقَمْحَ مِنْ مِصْرَ لِعِیَالِهِ فِی السَّنَهًِْ مَرَّتَیْنِ لِلشِّتَاءِ وَ الصَّیْفِ وَ إِنَّهُ بَعَثَ عِدَّهًًْ مِنْ وُلْدِهِ بِبِضَاعَهًٍْ یَسِیرَهًٍْ إِلَی مِصْرَ مَعَ رِفْقَهًٍْ خَرَجَتْ فَلَمَّا دَخَلُوا عَلَی یُوسُفَ (علیه السلام) وَ ذَلِکَ بَعْدَ مَا وَلَّاهُ الْعَزِیزُ مِصْرَ فَعَرَفَهُمْ یُوسُفُ (علیه السلام) وَ لَمْ یَعْرِفْهُ إِخْوَتُهُ لِهَیْبَهًِْ الْمَلِکِ وَ عِزِّهِ فَقَالَ لَهُمْ هَلُمُّوا بِضَاعَتَکُمْ قَبْلَ الرِّفَاقِ وَ قَالَ لِفِتْیَانِهِ عَجِّلُوا لِهَؤُلَاءِ الْکَیْلَ وَ أَوْفُوهُمْ فَإِذَا فَرَغْتُمْ فَاجْعَلُوا بِضَاعَتَهُمْ هَذِهِ فِی رِحَالِهِمْ وَ لَا تُعْلِمُوهُمْ بِذَلِکَ فَفَعَلُوا ثُمَّ قَالَ لَهُمْ یُوسُفُ (علیه السلام) قَدْ بَلَغَنِی أَنَّهُ کَانَ لَکُمْ أَخَوَانِ لِأَبِیکُمْ فَمَا فَعَلَا قَالُوا أَمَّا الْکَبِیرُ مِنْهُمَا فَإِنَّ الذِّئْبَ أَکَلَهُ وَ أَمَّا الصَّغِیرُ فَخَلَّفْنَاهُ عِنْدَ أَبِیهِ وَ هُوَ بِهِ ضَنِینٌ وَ عَلَیْهِ شَفِیقٌ قَالَ فَإِنِّی أُحِبُّ أَنْ تَأْتُونِی بِهِ مَعَکُمْ إِذَا جِئْتُمْ لِتَمْتَارُوا فَإِنْ لَمْ تَأْتُونِی بِهِ فَلا کَیْلَ لَکُمْ عِنْدِی وَ لا تَقْرَبُونِ قالُوا سَنُراوِدُ عَنْهُ أَباهُ وَ إِنَّا لَفاعِلُونَ* فَلَمَّا رَجَعُوا إِلی أَبِیهِمْ ... فَتَحُوا مَتاعَهُمْ فَوَجَدُوا بِضَاعَتَهُمْ فِیهِ قالُوا یا أَبانا ما نَبْغِی هذِهِ بِضاعَتُنا قَدْ رُدَّتْ إِلَیْنا وَ کِیلَ لَنَا کَیْلٌ قَدْ زَادَ حِمْلَ بَعِیرٍ فَأَرْسِلْ مَعَنا أَخانا نَکْتَلْ وَ إِنَّا لَهُ لَحافِظُونَ قالَ هَلْ آمَنُکُمْ عَلَیْهِ إِلَّا کَما أَمِنْتُکُمْ عَلی أَخِیهِ مِنْ قَبْلُ فَلَمَّا احْتَاجُوا إِلَی الْمِیرَهًِْ بَعْدَ سِتَّهًِْ أَشْهُرٍ بَعَثَهُمْ یَعْقُوبُ (علیه السلام) وَ بَعَثَ مَعَهُمْ بِضَاعَهًًْ یَسِیرَهًًْ وَ بَعَثَ مَعَهُمُ ابْنَ یَامِیلَ{یَامِینَ} وَ أَخَذَ عَلَیْهِمْ بِذَلِکَ مَوْثِقاً مِنَ اللَّهِ لَتَأْتُنَّنِی بِهِ إِلَّا أَنْ یُحاطَ بِکُمْ أَجْمَعِینَ فَانْطَلَقُوا مَعَ الرِّفَاقِ حَتَّی دَخَلُوا عَلَی یُوسُفَ (علیه السلام) فَقَالَ لَهُمْ مَعَکُمُ ابْنُ یَامِیلَ {یَامِینَ} قَالُوا نَعَمْ هُوَ فِی الرَّحْلِ قَالَ لَهُمْ فَأْتُوْنِی بِهِ فَأَتَوْهُ بِهِ وَ هُوَ فِی دَارِ الْمَلِکِ فَقَالَ أَدْخِلُوهُ وَحْدَهُ فَأَدْخَلُوهُ عَلَیْهِ فَضَمَّهُ یُوسُفُ (علیه السلام) إِلَیْهِ وَ بَکَی وَ قَالَ لَهُ أَنَا أَخُوکَ یُوسُفُ (علیه السلام) فَلَا تَبْتَئِسْ بِمَا تَرَانِی أَعْمَلُ وَ اکْتُمْ مَا أَخْبَرْتُکَ بِهِ وَ لَا تَحْزَنْ وَ لَا تَخَفْ ثُمَّ أَخْرَجَهُ إِلَیْهِمْ وَ أَمَرَ فِتْیَتَهُ أَنْ یَأْخُذُوا بِضَاعَتَهُمْ وَ یُعَجِّلُوا لَهُمُ الْکَیْلَ فَإِذَا فَرَغُوا جَعَلُوا الْمِکْیَالَ فِی رَحْلِ ابْنِ یَامِیلَ {یَامِینَ} فَفَعَلُوا بِهِ ذَلِکَ وَ ارْتَحَلَ الْقَوْمُ مَعَ الرِّفْقَهًِْ فَمَضَوْا فَلَحِقَهُمْ یُوسُفُ (علیه السلام) وَ فِتْیَتُهُ فَنَادَوْا فِیهِمْ أَیَّتُهَا الْعِیرُ إِنَّکُمْ لَسارِقُونَ قالُوا وَ أَقْبَلُوا عَلَیْهِمْ ما ذا تَفْقِدُونَ* قالُوا نَفْقِدُ صُواعَ الْمَلِکِ وَ لِمَنْ جاءَ بِهِ حِمْلُ بَعِیرٍ وَ أَنَا بِهِ زَعِیمٌ* قالُوا تَاللهِ لَقَدْ عَلِمْتُمْ ما جِئْنا لِنُفْسِدَ فِی الْأَرْضِ وَ ما کُنَّا سارِقِینَ* قالُوا فَما جَزاؤُهُ إِنْ کُنْتُمْ کاذِبِینَ* قالُوا جَزاؤُهُ مَنْ وُجِدَ فِی رَحْلِهِ فَهُوَ جَزاؤُهُ ... * قَالَ فَبَدَأَ بِأَوْعِیَتِهِمْ قَبْلَ وِعاءِ أَخِیهِ ثُمَّ اسْتَخْرَجَها مِنْ وِعاءِ أَخِیهِ ... قالُوا إِنْ یَسْرِقْ فَقَدْ سَرَقَ أَخٌ لَهُ مِنْ قَبْلُ ... فَقَالَ لَهُمْ یُوسُفُ ارْتَحِلُوا عَنْ بِلَادِنَا قالُوا یا أَیُّهَا الْعَزِیزُ إِنَّ لَهُ أَباً شَیْخاً کَبِیراً وَ قَدْ أَخَذَ عَلَیْنَا مَوْثِقاً مِنَ اللهِ لِنَرُدَّ بِهِ إِلَیْهِ فَخُذْ أَحَدَنا مَکانَهُ إِنَّا نَراکَ مِنَ الْمُحْسِنِینَ* إِنْ فَعَلْتَ قالَ مَعاذَ اللهِ أَنْ نَأْخُذَ إِلَّا مَنْ وَجَدْنا مَتاعَنا عِنْدَهُ ... فَقالَ کَبِیرُهُمْ إِنِّی لَسْتُ أَبْرَحُ الْأَرْضَ حَتَّی یَأْذَنَ لِی أَبِی أَوْ یَحْکُمَ اللَّهُ لِی وَ مَضَی إِخْوَهًُْ یُوسُفَ (علیه السلام) حَتَّی دَخَلُوا عَلَی یَعْقُوبَ (علیه السلام) فَقَالَ لَهُمْ فَأَیْنَ ابْنُ یَامِیلَ{یَامِینَ} قَالُوا ابْنُ یَامِیلَ {یَامِینَ} سَرَقَ مِکْیَالَ الْمَلِکِ فَأَخَذَ الْمَلِکُ سَرِقَتَهُ فَحَبَسَ عِنْدَهُ فَاسْأَلْ أَهْلَ الْقَرْیَهًِْ وَ الْعِیْرَ حَتَّی یُخْبِرُوکَ بِذَلِکَ فَاسْتَرْجَعَ وَ اسْتَعْبَرَ وَ اشْتَدَّ حُزْنُهُ حَتَّی تَقَوَّسَ ظَهْرُهُ.

امام صادق (علیه السلام)-

وقتی یعقوب (علیه السلام)، یوسف (علیه السلام) را از دست داد، به تدریج، غم و اندوه او در فراق یوسف (علیه السلام)، افزون شد و آنقدر گریست که چشمانش از اندوه، سفید شده و به فقر و بیچارگی گرفتار آمد. یعقوب (علیه السلام) سالی دوبار برای خانواده‌اش از مصر، آذوقه و گندم تهیّه می‌کرد؛ یک‌بار در فصل تابستان و بار دیگر در فصل زمستان. یعقوب (علیه السلام)، برخی از پسرانش را با مقدار ناچیزی کالا، همراه با کاروانی روانه‌ی مصر کرد، و این زمانی بود که عزیز مصر، حکمرانی را به یوسف (علیه السلام) داده بود. وقتی برادران بر یوس-ف (علیه السلام) وارد شدند، یوسف (علیه السلام) آنان را شناخت، امّا آن‌ها یوسف (علیه السلام) را به خاطر عظمت و شکوه حکومت و سلطنتش نشناختند. یوسف (علیه السلام) به برادران گفت: «زود باشید کالاهایتان را قبل از همراهانتان تحویل دهید». و به مأمورانش گفت: «بار این افراد را هرچه سریع‌تر آماده سازید و وقتی کار شما تمام شد، کالاهایی را که با خود آورده‌اند، در لابه‌لای بارهایشان جا دهید و نگذارید آن‌ها متوجّه این موضوع بشوند». و مأموران یوسف (علیه السلام) چنین کردند. سپس یوسف (علیه السلام) به برادران گفت: «به من خبر داده‌اند که شما دارای دو برادر ناتنی هستید، بگویید چه بر سر آن‌ها آمده است»؟ گفتند: «برادر بزرگتر را گرگ خورد، امّا برادر کوچکتر را نزد پدر که او را سخت دوست دارد و او را با کسی همراه نمی‌کند و به او بسیار ملاطفت می‌کند، گذاشته‌ایم». یوسف (علیه السلام) گفت: «دوست دارم دفعه‌ی بعد که برای بردن آذوقه به مصر می‌آیید، وی را با خود بیاورید. گفتند: «ما درباره‌ی او با پدرش گفتگو خواهیم کرد؛ و ما [این کار را] انجام خواهیم داد. (

یوسف/۶۱

)» وقتی نزد یعقوب (علیه السلام) برگشتند و کالاهایشان را باز کردند، متوجّه شدند که کالایی را که برای خرید اجناس به مصر برده بودند، در میان بارهایشان نهاده شده است؛ گفتند: پدر! ما دیگر چه می‌خواهیم؟! این سرمایه‌ی ماست که به ما باز پس گردانده شده است! (

یوسف/۶۵

) و به ما باری داده شده است که از بار شتر، افزون‌تر است. پس برادرمان را با ما بفرست، تا سهمی [از غلّه] دریافت داریم و ما او را محافظت خواهیم کرد»! گفت: «آیا نسبت به او به شما اطمینان کنم همان‌گونه که نسبت به برادرش [یوسف] اطمینان کردم. (

یوسف/۶۴-۶۳

) و شش ماه بعد، زمانی‌که نیاز به تهیّه‌ی آذوقه داشتند، یعقوب (علیه السلام)، آنان را همراه با اندک کالایی، روانه‌ی مصر کرد و این‌بار، بنیامین را نیز با آنان فرستاد و از آنان پیمان‌الهی گرفت که بنیامین را بازگردانند، مگر آنکه هیچ‌یک باز نیایند. پسران یعقوب (علیه السلام)، همراه با کاروانیان راهی مصر شده و نزد یوسف (علیه السلام) رفتند. یوسف (علیه السلام) پرسید: «بنیامیل، شما را همراهی کرده است»؟ گفتند: «آری، او اکنون در میان کاروانیان است». یوسف (علیه السلام) گفت: «او را نزد من بیاورید. برادران، بنیامیل را نزد یوسف (علیه السلام) [که در کاخ شاهی بود] آوردند». یوسف (علیه السلام) گفت: «بنیامین را به تنهایی وارد کنید». مأموران یوسف (علیه السلام)، او را تنها به حضور یوسف (علیه السلام) آوردند. یوسف (علیه السلام)، بنیامین را در آغوش کشید و گریست و به او گفت: «منم برادرت یوسف (علیه السلام)! نگران رفتار من با برادران مباش و آنچه را که میان من و تو گذشت، کتمان کن و غم به دل راه مده و نترس». سپس بنیامین را نزد برادران برد و به مأموران خود دستور داد، کالاهایی را که با خود آورده‌اند، تحویل دهند و هرچه سریع‌تر گندم آن‌ها را بار کرده و وزن کنند و وقتی کار با گندم‌ها تمام شد، پیمانه را در بار بنیامین جاسازی کنند؛ و مأموران یوسف (علیه السلام) نیز چنین کردند. برادران یوسف (علیه السلام) همراه با کاروانیان به راه خود ادامه دادند و رفتند، امّا یوسف (علیه السلام) و مأمورانش آنان را دنبال کرده و بر آنان بانگ زدند و گفتند: ای اهل قافله! شما سارقید، [برادران یوسف] رو به‌سوی آن‌ها کردند و گفتند: «چه چیز گم کرده‌اید»؟، گفتند: «جام مخصوص پادشاه را! و هرکس آن را بیاورد، یک‌بارِ شتر [غلّه] به او داده می‌شود؛ و من ضامن این [پاداش] هستم». گفتند: «به خدا سوگند شما می‌دانید ما نیامده‌ایم که در این سرزمین فساد کنیم؛ و ما هیچ‌گاه دزد نبوده‌ایم»! آن‌ها گفتند: «اگر دروغگو باشید، کیفرش چیست»؟ گفتند: «هرکس [آن جام] در بارِ او پیدا شود، خودش کیفر آن خواهد بود. (

یوسف/۷۵-۷۰

) گفت: دراین‌هنگام، [یوسف] قبل از بارِ برادرش، به کاوش بارهای آن‌ها [سایر برادرانش] پرداخت؛ سپس آن را از بارِ برادرش (بنیامین) بیرون آورد، گفتند: اگر او دزدی کرده، برادرش نیز پیش از این دزدی‌کرده بود. (

یوسف/۷۷-۷۶

) یوسف (علیه السلام) به آنان گفت: «از سرزمین ما بیرون روید». گفتند: «ای عزیز! او پدر بسیار پیری دارد [که طاقت دوری او را ندارد]. (

یوسف/۷۸

) و از ما پیمان‌الهی گرفته که او را نزد پدر برگردانیم یکی از ما را به‌جای او بگیر؛ اگر این رفتار را با ما انجام دهی، ما تو را از نیکوکاران می‌بینیم. (

یوسف/۷۸

). گفت: معاذ اللَّه که جز آن کس را که کالای خویش نزد او یافته‌ایم بگیریم. (

یوسف/۷۹

) برادر بزرگ گفت: تا زمانی‌که پدرم به من اجازه نداده و یا خداوند، درباره‌ی من دستور و حکمی صادر نکند، من این مکان را ترک نخواهم کرد. برادران یوسف (علیه السلام) راه خود را پی گرفته و بر یعقوب (علیه السلام) وارد شدند. یعقوب (علیه السلام) از پسرانش پرسید: «پس بنیامین کجاست»؟ گفتند: «بنیامین، پیمانه‌ی شاهی را دزدید و پادشاه هم او را به خاطر دزدی پیمانه گروگان گرفت و هم اکنون نزد پادشاه زندانی است، پدر! اگر به ما اعتمادی نداری، از مردم آنجا و یا قافله‌ای که در آن بودیم، سؤال کن تا تو را به حقیقت ماجرا آگاه سازند». یعقوب (علیه السلام) استرجاع؛ إِنَّا لِلهِ وَ إِنَّا إِلَیْهِ راجِعُونَ (

بقره/۱۵۶

) را گفت و گریه کرد و اندوهش افزوده شد، به‌طوری‌که پشتش خمیده گشت.

تفسیر اهل بیت علیهم السلام ج۷، ص۱۰۶

بحارالأنوار، ج۱۲، ص۱۲/ العیاشی، ج۲، ص۱۸۱/ البرهان/ البرهان

entries.persian:
وقتی یعقوب (علیه السلام)، یوسف (علیه السلام) را از دست داد، به تدریج، غم و اندوه او در فراق یوسف (علیه السلام)، افزون شد و آنقدر گریست که چشمانش از اندوه، سفید شده و به فقر و بیچارگی گرفتار آمد. یعقوب (علیه السلام) سالی دوبار برای خانواده‌اش از مصر، آذوقه و گندم تهیّه می‌کرد؛ یک‌بار در فصل تابستان و بار دیگر در فصل زمستان. یعقوب (علیه السلام)، برخی از پسرانش را با مقدار ناچیزی کالا، همراه با کاروانی روانه‌ی مصر کرد، و این زمانی بود که عزیز مصر، حکمرانی را به یوسف (علیه السلام) داده بود. وقتی برادران بر یوس-ف (علیه السلام) وارد شدند، یوسف (علیه السلام) آنان را شناخت، امّا آن‌ها یوسف (علیه السلام) را به خاطر عظمت و شکوه حکومت و سلطنتش نشناختند. یوسف (علیه السلام) به برادران گفت: «زود باشید کالاهایتان را قبل از همراهانتان تحویل دهید». و به مأمورانش گفت: «بار این افراد را هرچه سریع‌تر آماده سازید و وقتی کار شما تمام شد، کالاهایی را که با خود آورده‌اند، در لابه‌لای بارهایشان جا دهید و نگذارید آن‌ها متوجّه این موضوع بشوند». و مأموران یوسف (علیه السلام) چنین کردند. سپس یوسف (علیه السلام) به برادران گفت: «به من خبر داده‌اند که شما دارای دو برادر ناتنی هستید، بگویید چه بر سر آن‌ها آمده است»؟ گفتند: «برادر بزرگتر را گرگ خورد، امّا برادر کوچکتر را نزد پدر که او را سخت دوست دارد و او را با کسی همراه نمی‌کند و به او بسیار ملاطفت می‌کند، گذاشته‌ایم». یوسف (علیه السلام) گفت: «دوست دارم دفعه‌ی بعد که برای بردن آذوقه به مصر می‌آیید، وی را با خود بیاورید. گفتند: «ما درباره‌ی او با پدرش گفتگو خواهیم کرد؛ و ما [این کار را] انجام خواهیم داد. (

یوسف/۶۱

)» وقتی نزد یعقوب (علیه السلام) برگشتند و کالاهایشان را باز کردند، متوجّه شدند که کالایی را که برای خرید اجناس به مصر برده بودند، در میان بارهایشان نهاده شده است؛ گفتند: پدر! ما دیگر چه می‌خواهیم؟! این سرمایه‌ی ماست که به ما باز پس گردانده شده است! (

یوسف/۶۵

) و به ما باری داده شده است که از بار شتر، افزون‌تر است. پس برادرمان را با ما بفرست، تا سهمی [از غلّه] دریافت داریم و ما او را محافظت خواهیم کرد»! گفت: «آیا نسبت به او به شما اطمینان کنم همان‌گونه که نسبت به برادرش [یوسف] اطمینان کردم. (

یوسف/۶۴-۶۳

) و شش ماه بعد، زمانی‌که نیاز به تهیّه‌ی آذوقه داشتند، یعقوب (علیه السلام)، آنان را همراه با اندک کالایی، روانه‌ی مصر کرد و این‌بار، بنیامین را نیز با آنان فرستاد و از آنان پیمان‌الهی گرفت که بنیامین را بازگردانند، مگر آنکه هیچ‌یک باز نیایند. پسران یعقوب (علیه السلام)، همراه با کاروانیان راهی مصر شده و نزد یوسف (علیه السلام) رفتند. یوسف (علیه السلام) پرسید: «بنیامیل، شما را همراهی کرده است»؟ گفتند: «آری، او اکنون در میان کاروانیان است». یوسف (علیه السلام) گفت: «او را نزد من بیاورید. برادران، بنیامیل را نزد یوسف (علیه السلام) [که در کاخ شاهی بود] آوردند». یوسف (علیه السلام) گفت: «بنیامین را به تنهایی وارد کنید». مأموران یوسف (علیه السلام)، او را تنها به حضور یوسف (علیه السلام) آوردند. یوسف (علیه السلام)، بنیامین را در آغوش کشید و گریست و به او گفت: «منم برادرت یوسف (علیه السلام)! نگران رفتار من با برادران مباش و آنچه را که میان من و تو گذشت، کتمان کن و غم به دل راه مده و نترس». سپس بنیامین را نزد برادران برد و به مأموران خود دستور داد، کالاهایی را که با خود آورده‌اند، تحویل دهند و هرچه سریع‌تر گندم آن‌ها را بار کرده و وزن کنند و وقتی کار با گندم‌ها تمام شد، پیمانه را در بار بنیامین جاسازی کنند؛ و مأموران یوسف (علیه السلام) نیز چنین کردند. برادران یوسف (علیه السلام) همراه با کاروانیان به راه خود ادامه دادند و رفتند، امّا یوسف (علیه السلام) و مأمورانش آنان را دنبال کرده و بر آنان بانگ زدند و گفتند: ای اهل قافله! شما سارقید، [برادران یوسف] رو به‌سوی آن‌ها کردند و گفتند: «چه چیز گم کرده‌اید»؟، گفتند: «جام مخصوص پادشاه را! و هرکس آن را بیاورد، یک‌بارِ شتر [غلّه] به او داده می‌شود؛ و من ضامن این [پاداش] هستم». گفتند: «به خدا سوگند شما می‌دانید ما نیامده‌ایم که در این سرزمین فساد کنیم؛ و ما هیچ‌گاه دزد نبوده‌ایم»! آن‌ها گفتند: «اگر دروغگو باشید، کیفرش چیست»؟ گفتند: «هرکس [آن جام] در بارِ او پیدا شود، خودش کیفر آن خواهد بود. (

یوسف/۷۵-۷۰

) گفت: دراین‌هنگام، [یوسف] قبل از بارِ برادرش، به کاوش بارهای آن‌ها [سایر برادرانش] پرداخت؛ سپس آن را از بارِ برادرش (بنیامین) بیرون آورد، گفتند: اگر او دزدی کرده، برادرش نیز پیش از این دزدی‌کرده بود. (

یوسف/۷۷-۷۶

) یوسف (علیه السلام) به آنان گفت: «از سرزمین ما بیرون روید». گفتند: «ای عزیز! او پدر بسیار پیری دارد [که طاقت دوری او را ندارد]. (

یوسف/۷۸

) و از ما پیمان‌الهی گرفته که او را نزد پدر برگردانیم یکی از ما را به‌جای او بگیر؛ اگر این رفتار را با ما انجام دهی، ما تو را از نیکوکاران می‌بینیم. (

یوسف/۷۸

). گفت: معاذ اللَّه که جز آن کس را که کالای خویش نزد او یافته‌ایم بگیریم. (

یوسف/۷۹

) برادر بزرگ گفت: تا زمانی‌که پدرم به من اجازه نداده و یا خداوند، درباره‌ی من دستور و حکمی صادر نکند، من این مکان را ترک نخواهم کرد. برادران یوسف (علیه السلام) راه خود را پی گرفته و بر یعقوب (علیه السلام) وارد شدند. یعقوب (علیه السلام) از پسرانش پرسید: «پس بنیامین کجاست»؟ گفتند: «بنیامین، پیمانه‌ی شاهی را دزدید و پادشاه هم او را به خاطر دزدی پیمانه گروگان گرفت و هم اکنون نزد پادشاه زندانی است، پدر! اگر به ما اعتمادی نداری، از مردم آنجا و یا قافله‌ای که در آن بودیم، سؤال کن تا تو را به حقیقت ماجرا آگاه سازند». یعقوب (علیه السلام) استرجاع؛ إِنَّا لِلهِ وَ إِنَّا إِلَیْهِ راجِعُونَ (

بقره/۱۵۶

) را گفت و گریه کرد و اندوهش افزوده شد، به‌طوری‌که پشتش خمیده گشت.

از ابن‌عبّاس (رحمة الله علیه) در مورد پیمانی که یعقوب (علیه السلام) از فرزندانش گرفت سؤال شد. در جواب فرمود: «یعقوب (علیه السلام) به آن‌ها گفت: «ای فرزندانم! باید فرزندم [بنیامین] را بازگردانید در غیر این‌صورت شما از پیامبر اُمّی [از صفات پیامبر اسلام (صلی الله علیه و آله)] که در آخرالزّمان مبعوث خواهد شد بیزارید، او پیروانی دارد که به‌سوی حق هدایت می‌کنند و به حق و عدالت حکم می‌نمایند، او صاحب کلام با عظمتی است که عظمتش از آسمان‌ها و زمین بیشتر می‌باشد؛ [یعنی] لا إله إلا الله محمّد رسول الله علی ولی الله او صاحب شتر ماده [شتری که پیامبر اسلام (صلی الله علیه و آله) بر آن سوار می‌شدند و نامش «عضباء» بوده] و «قضیب» [نام یکی از شمشیرهای پیامبر اسلام (صلی الله علیه و آله)] است و خداوند او را حبیبِ خود نامیده است. او صاحب چهره‌ای همچون ماه و پیشانی درخشان و صاحب حوض و کوثر و مقام مشهود [اشاره به شهود کامل پیامبر (صلی الله علیه و آله) در شب معراج] است؛ پسر عمویی دارد که به او «حیدر» گویند و شوهر دختر او و جانشین او میان امّتش می‌باشد و نامش علیّ‌بن‌ابی‌طالب (علیه السلام) است. اگر شما در مورد فرزندم [بنیامین] به من خیانت کنید [و او را بازنگردانید] در روز قیامت درحالی با او روبرو خواهید شد که او از شما روی بر می‌گرداند. برادران گفتند: «آری! [چنین پیمانی می‌بندیم]». آنگاه یعقوب (علیه السلام) گفت: و [در هر حال]، خداوند بهترین حافظ، و مهربان‌ترین مهربانان است. (

یوسف/۶۴

) آن‌ها نیز گفتند: «آری! و [در هر حال]، خداوند بهترین حافظ، و مهربان‌ترین مهربانان است. (

یوسف/۶۴

)».

ابان احمر از امام صادق (علیه السلام) روایت می‌کند که فرمود: وقتی برادران یوسف (علیه السلام) نزد او آمدند و بنیامین نیز آنان را همراهی می‌کرد، یوسف (علیه السلام) برای آنان سفره‌ی غذا تدارک دیده و گفت: هر دو نف-ر از شما که مادرت-ان یکی اس-ت با هم سر یک سف-ره بنش-یند. همگی چنان کردند و برادرش بنیامین تنها ماند. یوسف (علیه السلام) به او گفت: «تو چرا با یکی از برادران بر سر یک سفره نمی‌نشینی»؟ بنیامین گفت: «در میان آنان، هیچ‌کدام از طرف مادر، برادر من نیست». یوسف (علیه السلام) پرسید: «آیا تو از طرف مادر، برادری داری که این جماعت برآنند که گرگ او را خورده است»؟ گفت: «آری». یوسف (علیه السلام) گفت: «بنشین و با من غذا بخور». برادران چون این صحنه را دیدند، از خوردن دست کشیدند و گفتند: «ما دنبال سربلندی و عزّت خود هستیم، امّا خواست خدا چیزی دیگری است، گویا خداوند، فقط می‌خواهد پسران یامین را در مرتبه‌ای بالاتر از ما قرار دهد». وقتی آماده‌ی رفتن به دیار خود شدند و بارهایشان بسته شد، یوسف (علیه السلام) فرمان داد که پیمانه را در بار بنیامین بگذارند. وقتی کاروان برادران یوسف (علیه السلام) از آن دیار رفتند، منادی یوسف (علیه السلام) بانگ برآورد که؛ ای اهل قافله، شما دزد هستید!. (

یوسف/۷۰

) وقتی آنان متوجّه صدا شدند، برگشتند و گفتند: «چه چیز گم کرده‌اید»؟، گفتند: «جام مخصوص پادشاه را! و هرکس آن را بیاورد، یک‌بارِ شتر [غلّه] به او داده می‌شود؛ و من ضامن این [پاداش] هستم». گفتند: «به خدا سوگند شما می‌دانید ما نیامده‌ایم که در این سرزمین فساد کنیم؛ و ما هیچ‌گاه دزد نبوده‌ایم»! آن‌ها گفتند: «اگر دروغگو باشید، کیفرش چیست»؟ گفتند: «هرکس [آن جام] در بارِ او پیدا شود، خودش کیفر آن خواهد بود». (

یوسف/۷۵-۷۰

). مقصودشان، همان قانونی بوده که در میان خود آن‌ها اجرا می‌شده است؛ یعنی اگر شیء دزدیده شده را نزد هرکس پیدا می‌کردند، او را به زندان می‌انداختند. پیش از بار برادر به بار آن‌ها پرداخت، آنگاه از بار برادرش بیرونش آورد. (

یوسف/۷۶

) [برادران] گفتند: «اگر او [بنیامین] دزدی کند، [جای تعجّب نیست] برادرش (یوسف) نیز قبل از او دزدی کرد». (

یوسف/۷۷

)».

هنگامی‌که برادران یوسف (علیه السلام) به همراه بنیامین بر او وارد شدند یوسف (علیه السلام) برایشان سفره‌های غذا گستراند و گفت: «هرکدام از شما با برادر مادری خود بر سر سفره بنشیند و هم غذا شود». آن‌ها نیز چنین کردند ولی بنیامین همچنان ایستاده بود. یوسف (علیه السلام) به او گفت: «چرا تو با برادرانت نمی‌نشینی»؟! در جواب گفت: «من در میان این‌ها برادر مادری ندارم». یوسف (علیه السلام) گفت: «تو برادری مادری داری که این‌ها گمان می‌کنند گرگ او را خورده است»؟ گفت: «آری»! یوسف (علیه السلام) گفت: «بنشین و با من هم‌غذا شو»! دراین‌هنگام برادران، دست از خوردن کشیده و گفتند: «ما به‌دنبال رسیدن به خواسته‌ی خود [سروری و جانشینی بعد از یعقوب (علیه السلام)] هستیم ولی خدا اراده کرده است که فرزند «بنیامین» [نام م-ادر یوسف (علیه السلام) و بنیامین که البتّه نام اص-لی‌اش «راح-یل» بوده» را بر م-ا برتری دهد». هنگامی‌که مأموران بارهای آنان را بستند یوسف (علیه السلام) دستور داد پیمانه را در بار بنیامین قرار دهند؛ چون برادران به راه افتادند کسی صدا زد: «ای اهل قافله! شما سارقید». برادران برگشته و گفتند: چه چیز گم کرده‌اید؟. (

یوسف/۷۱

) پیمانه پادشاه را! و هرکس آن را بیاورد، یک‌بار شتر (غلّه) به او داده می‌شود و من ضامن این (پاداش) هستم»! گفتند: «به خدا سوگند شما می‌دانید ما نیامده‌ایم که در این سرزمین فساد کنیم و ما [هرگز] دزد نبوده‌ایم»! آن‌ها گفتند: «اگر دروغگو باشید، کیفرش چیست»؟ گفتند: «هرکس [آن پیمانه] در بارِ او پیدا شود، خودش کیفر آن خواهد بود. (

یوسف/۷۵-۷۲

) مراد آن‌ها شیوه‌ای بود که در میان خودشان معمول بود یعنی یوسف (علیه السلام)، می‌تواند دزد را نزد خود نگهدارد دراین‌هنگام، [یوسف] قبل از بار برادرش، به کاوش بارهای آن‌ها پرداخت. (

یوسف/۷۶

) دراین‌هنگام [برادران] گفتند: «اگر او (بنیامین) دزدی کند، [جای تعجّب نیست] برادرش (یوسف) نیز قبل از او دزدی کرد. (

یوسف/۷۷

).

حسن‌بن‌صیقل گوید: به امام صادق (علیه السلام) عرض کردم: «از امام باقر (علیه السلام) درباره‌ی جمله‌ای که یوسف (علیه السلام) در این آیه که گفته: أَیَّتُهَا الْعِیرُ إِنَّکُمْ لَسَارِقُونَ روایت شده است که امام (علیه السلام) فرمود: به خداوند قسم! که آنان دزدی نکرده بودند و یوسف (علیه السلام) هم دروغ نگفت. و ابراهیم (علیه السلام) [هم] گفته است: بلکه بزرگ‌ترینشان چنین کرده است. اگر سخن می‌گویند از آن‌ها بپرسید. (

انبیاء/۶۳

) که امام باقر (علیه السلام) فرموده است: «به خدا قسم! آن بت‌ها چنان نکرده بودند و ابراهیم (علیه السلام) هم دروغ نگفته بود». امام صادق (علیه السلام) در توضیح آن فرمود: «ای صیقل! نظر شما چیست»؟ عرض کردم: «ما جز تسلیم و پذیرش به رأی شما، در این‌باره هیچ نظر و دیدگاهی نداریم». امام صادق (علیه السلام) فرمود: «خداوند دو چیز را می‌پسندد و از دو چیز، بیزار است: خرامیدن و خودپسندانه راه‌رفتن در میان دو لشکر. دروغ مصلحت‌آمیز را هم دوست دارد؛ امّا خرامیدن در کوچه و بازار و بین مردم را نمی‌پسندد و از دروغی که برای مصلحت نباشد، بیزار است. وقتی حضرت ابراهیم (علیه السلام) این آیه‌ی؛ بلکه این کار را بزرگشان کرده است!. (

انبیاء/۶۳

) را فرمود، تنها قصد اصلاح داشت، به این دلیل که بت‌ها نمی‌توانستند کاری انجام دهند؛ یوسف (علیه السلام) هم به قصد اصلاح، چنین گفت.

ابوبصیر گوید: امام صادق (علیه السلام) فرمود: «سالم‌بن‌حفصه از شما روایت می‌کند که شما به هفتادگونه سخن می‌گویید و می‌توانید از همه‌ی آن‌ها روزنه‌ای پیدا کنید و بیرون آیید». امام (علیه السلام) فرمود: «سالم چه توقعی از من دارد؟ مثل اینکه می‌خواهد برای صدق ادّعایم فرشته‌ها را به زمین بیاورم؛ به خدا قسم! پیامبران نیز در اثبات خود فرشتگان را به گواهی نیاورده‌اند». حضرت ابراهیم (علیه السلام) فرمود: من بیمارم [و با شما به مراسم جشن نمی‌آیم]. (

صافات/۸۹

). و به خدا قسم مریض نبود، امّا دروغ هم نگفت؛ همو فرمود: بلکه بزرگ‌ترینشان چنین کرده است. (

انبیاء/۶۳

). و این بت بزرگ نبود که آن بلا را بر سر بت‌ها درآورد، با این وصف ابراهیم (علیه السلام) دروغ نگفت. یوسف (علیه السلام) گفت: أَیَّتُهَا الْعِیرُ إِنَّکُمْ لَسَارِقُونَ به خدا سوگند که آن‌ها چیزی ندزدیده بودند و یوسف (علیه السلام) هم دروغ نگفت.

دلیل بر اینکه کید به‌معنای حیله و تدبیر است، سخن خداوند متعال است که می‌فرماید: کَذلِکَ کِدْنا لِیُوسُفَ یعنی برای یوسف (علیه السلام) تدبیر اندیشیدیم تا اینکه بتواند برادرش را نزد خود نگهدارد؛ همچنین در آنجا که سخن فرعون را نقل می‌کند که گفت: فَأَجْمِعُوا کَیْدَکُمْ؛ اکنون که چنین است، تمام نیرو و نقشه‌ی خود را جمع کنید (

طه/۶۴

) به‌معنای این است که همه‌ی حیله‌تان را به کاربندید.

در یکی از روزهایی که پیامبر اسلام (صلی الله علیه و آله) در خانه‌ی امّ سلمه بودند جبرئیل بر آن حضرت نازل شد و عرض کرد: «ای محمّد (صلی الله علیه و آله)! گروهی از فرشتگانِ آسمان چهارم در مورد موضوعی با یکدیگر به جدال پرداخته‌اند و نزاع بالا گرفته است و این‌ها گروهی از جنّیان و از قوم ابلیسی هستند که خداوند در کتابش می‌فرماید: جز ابلیس - که از جن بود - و از فرمان پروردگارش بیرون شد. (

کهف/۵۰

) در این‌حال، خداوند متعال به این گروه از فرشتگان وحی فرمود: «جدال میان شما بالا گرفته پس به قضاوت یک‌نفر از انسان‌ها رضایت دهید تا میان شما قضاوت کند». عرض کردند: «ما به قضاوت یک‌نفر از امّت محمّد (صلی الله علیه و آله) راضی هستیم؛ خداوند فرمود: «به چه کسی از امّت محمّد (صلی الله علیه و آله) راضی می‌شوید»؟ عرض کردند: «ما به علیّ‌بن‌ابی‌طالب (علیه السلام) راضی هستیم». در این‌هنگام خداوند یکی از فرشتگان آسمانِ دنیا را به همراه یک فرش و دو متکّای آراسته به زمین فرستاد و او نزد پیامبر اسلام (صلی الله علیه و آله) رفت و ایشان را از جریان باخبر ساخت. پیامبر (صلی الله علیه و آله) نیز علیّ‌بن‌ابی‌طالب (علیه السلام) را خواسته و او را بر آن فرش نشانده و دو متکّا را پشت او قرار داد و آب دهان مبارک خود را در دهان او ریخت و به او فرمود: «ای علی (علیه السلام)! خداوند دلت را استوار و برهانت را میان دو چشمانت آشکار سازد». آنگاه فرشته، علی (علیه السلام) را به آسمان برد. هنگامی‌که علی (علیه السلام) به زمین بازگشت عرض کرد: «ای محمّد (صلی الله علیه و آله)! خداوند به شما سلام می‌رساند و می‌فرماید: نَرْفَعُ دَرَجاتٍ مَنْ نَشاءُ وَ فَوْقَ کُلِّ ذِی عِلْمٍ عَلِیمٌ».

علیّ‌بن‌ابراهیم (رحمة الله علیه) و چون خواستند نزد پدر خویش برگردند، لاوی پسر یعقوب (علیه السلام) به برادران گفت: أَ‌لَمْ تَعْلَمُوا أَنَّ أَباکُمْ قَدْ أَخَذَ عَلَیْکُمْ مَوْثِقاً مِنَ اللهِ در این مسئله وَ مِنْ قَبْلُ ما فَرَّطْتُمْ فِی یُوسُفَ شما نزد پدر برگردید، اما من به سوی او باز نمی‌گردم. حَتَّی یَأْذَنَ لِی أَبِی أَوْ یَحْکُمَ اللهُ لِی وَ هُوَ خَیْرُ الْحاکِمِینَ سپس به آنان گفت: ش-ما به‌سوی پدرتان بازگردید و بگ-ویید: «پ-در [جان]، پس-رت سرقت کرد و ما جز به‌آنچه آگاه بودیم گواهی ندادیم و ما از غیب باخبر نبودیم. [و اگر اطمینان نداری]، از آن شهر که در آن بودیم سؤال کن، و نیز از آن قافله که با آن آمدیم [بپرس]؛ و ما [در گفتار خود] صادق هستیم». (

یوسف/۸۲-۸۱

) یعنی اهالی این آبادی و مردم این قافله‌ای که ما با آن بودیم برادران یوسف (علیه السلام)، نزد پدر برگشته و یهودا باقی ماند و نزد یوسف (علیه السلام) آمد و با او صحبت کرد و گفتگوی آنان بالا گرفت. یهودا خشمگین شد. بر روی دوش یهودا، مویی بود و خون از آن موی، سرازیر شد. این خون باز نمی‌ایستاد، تا اینکه یکی از فرزندان یعقوب (علیه السلام)، یهودا را لمس کند. امام (علیه السلام) فرمود: «یوسف (علیه السلام)، پسری داشت که در آنجا حاضر بود. در دست پسر یوسف (علیه السلام)، اناری از جنس طلا وجود داشت که با آن بازی می‌کرد. وقتی یوسف (علیه السلام) دید که یهودا عصبانی شده و آن موی، سیخ شده و پیاپی از آن خون می‌ریزد، انار را از دست کودک گرفته و آن را به‌سوی یهودا غلتاند. کودک، انار را دنبال کرد تا آن را بردارد و در همین حال، دست او با بدن یهودا تماس پیدا کرد و خشمش فرونشست. در این لحظه یهودا، دچار تردید شد. کودک همراه با انار به‌سوی یوسف (علیه السلام) برگشت؛ امّا بار دیگر، جرّ‌وبحث میان آن دو بالا گرفت و یهودا بار دیگر خشمگین شد و خون از موی شانه‌ی یهودا سرازیر گشت. همین‌که یوسف (علیه السلام) این منظره را مشاهده کرد، انار را به‌سوی یهودا غلتاند و کودک، آن را دنبال کرد تا بردارد؛ و دستش به بدن یهودا برخورد کرد و خشم او فرو نشست، یهودا گفت: «بی‌گمان در این خانه کسی از فرزندان یعقوب (علیه السلام) حضور دارد. و این کار، سه‌بار تکرار شد».

وقتی برادران یوسف (علیه السلام) از برادرشان ناامید شدند و دل کندند، یهودا که برادر بزرگ‌ترشان بود، گفت: لَنْ أَبْرَحَ الأَرْضَ حَتَّیَ یَأْذَنَ لِی أَبِی أَوْ یَحْکُمَ الله لِی وَ هُوَ خَیْرُ الحَاکِمِینَ. یهودا نزد یوسف (علیه السلام) برگشت و درباره‌ی بنیامین با وی صحبت کرد. جرّوبحث یهودا با یوسف (علیه السلام) بالا گرفت و یهودا عصبانی شد و هر وقت عصبانی می‌شد تار مویی که بر شانه‌اش بود، سیخ می‌شد و از آن خون جاری می‌گشت. یوسف (علیه السلام)، پسری خردسال داشت که با اناری از جنس طلا، بازی می‌کرد، وقتی یهودا بر سر بنیامین با یوسف (علیه السلام)، جرّ‌وبحث می‌کرد، یوسف (علیه السلام) آن انار طلایی را به‌سوی یهودا غلتاند و کودک، چهار دست و پا رفت تا انار را بگیرد؛ و چون یهودا، کودک را لمس کرد، آرام گرفت. سپس کودک، نزد یوسف (علیه السلام) بازگشت. یهودا دوباره بحث درباره‌ی برادرش را با یوسف (علیه السلام) آغاز کرد. این بحث به اوج خود رسید و [باز] یهودا عصبانی شد و آن مویی که بر شانه‌اش بود، راست شد و خون از آن بیرون آمد، در این لحظه، یوسف (علیه السلام)، انار را از کودک گرفت و آن را به‌س-مت یهودا غلت-اند و دوباره کودک، چهار دست و پا به‌سوی یهودا رفت تا انارش را بگیرد، یهودا دوباره با لمس کودک آرام شد و گفت: «با ما در این خانه، یکی از فرزندان یعقوب (علیه السلام) وجود دارد». دراین‌هنگام یوسف (علیه السلام) به آنان گفت: آیا دانستید با یوسف و برادرش چه کردید، آنگاه که جاهل بودید؟! (

یوسف/۸۹

)

امّا آن دسته از آیات قرآن که لفظشان یکی است و معنایی خلاف ظاهر دارند مثل آیه‌ی وَ سْئَلِ الْقَرْیَةَ الَّتِی کُنَّا فِیها وَ الْعِیرَ الَّتِی أَقْبَلْنا فِیها که مراد، اهل شهر و اهل قافله است و آیه: وَ تِلْکَ الْقُری أَهْلَکْناهُمْ لَمَّا ظَلَمُوا (

کهف/۵۹

) که مراد، اهل آن شهرهاست و آیه: وَ کَذلِکَ أَخْذُ رَبِّکَ إِذا أَخَذَ الْقُری وَ هِیَ ظالِمَةٌ (

هود/۱۰۲

) یعنی اهل آن شهرها است.

جابر نقل می‌کند: به امام باقر (علیه السلام) عرض کردم: «فَصَبْرٌ جَمِیلٌ چیست»؟ فرمود: «صبری است که فرد با احدی از مردم، درد دل نمی‌کند». حضرت ابراهیم (علیه السلام)، یعقوب (علیه السلام) را نزد یکی از راهبان و عابدان آن روزگار، جهت انجام کاری فرستاد. زمانی‌که آن راهب، یعقوب (علیه السلام) را مشاهده کرد، خیال کرد که ابراهیم (علیه السلام) است، پس برخاست و او را در آغوش گرفت و به او گفت: «ای خلیل الرحمن! خوش آمدی». یعقوب (علیه السلام) گفت: «من خلیل الرحمن نیستم، من یعقوب‌بن‌اسحاق بن‌ابراهیم (علیه السلام) هستم». راهب به او گفت: «پس چه شده که این قدر پیر شده‌ای»؟ یعقوب (علیه السلام) گفت: «اندوه و غم و بیماری». امام (علیه السلام) فرمود: «هنوز از آستانه‌ی در عبور نکرده بود که خداوند متعال به او وحی کرد که؛ ای یعقوب (علیه السلام)! درد دلت را با بندگان در میان گذاشتی»؟! یعقوب (علیه السلام) بلافاصله با صورت بر خاک افتاد و سجده‌کنان گفت: «پروردگارا! تکرار نخواهم کرد». پس خداوند به او وحی کرد که؛ «من نیز از تو درگذشتم و تو را آمرزیدم، دیگر چنین مکن». یعقوب (علیه السلام)، بعد از آن، هرگز از بلاها و سختی‌ها و مصائب روزگار، شکایت نکرد؛ فقط یک‌روز گفت: من غم و اندوهم را تنها به خدا می‌گویم [و شکایت نزد او می‌برم]! و از خدا چیزهایی می‌دانم که شما نمی‌دانید! (

یوسف/۸۶

).

یعقوب (علیه السلام) برای درخواست حاجتش نزد پادشاهی که در آن منطقه حکم می‌راند، رفت. پادشاه از یعقوب (علیه السلام) پرسید: «تو ابراهیم (علیه السلام) هستی»؟ یعقوب (علیه السلام) گفت: «نه». پادشاه پرسید: «پس اسحاق فرزند ابراهیمی»؟ گفت: «نه». پادشاه پرسید: «پس تو کیستی»؟ گفت: «من یعقوب پسر اسحاق (علیه السلام) هستم». پادشاه گفت: «چگونه است که در عین جوانی، چنین پیر و فرتوت شده‌ای»؟ یعقوب (علیه السلام) گفت: «اندوه پسرم یوسف (علیه السلام)، مرا به‌چنین روزی انداخته است». پادشاه گفت: «واقعاً غم و اندوه، کار خویش را با تو کرده است». یعقوب (علیه السلام) گفت: «مصیبت و بلا، زودتر از هر چیز دیگری بر ما جماعت پیامبران می‌رسد؛ سپس مردمان دیگر، هرچه به درگاه خداوند مقرّب‌تر باشند، بیشتر به بلا مبتلا می‌شوند». آن پادشاه خواسته‌ی یعقوب (علیه السلام) را برآورده کرد و وقتی یعقوب (علیه السلام) خواست از در کوچک خانه‌اش وارد منزل شود، جبرئیل بر او فرود آمده و گفت: «ای یعقوب (علیه السلام)! پروردگار به تو سلام می‌رساند و می‌فرماید: «در پیشگاه مردم شکوه می‌کنی و لب به گلایه می‌گشایی»؟! یعقوب (علیه السلام) بلافاصله، چهره بر خاک گذاشت و متضرّعانه به درگاه پروردگار عرض کرد: «پروردگارا! لغزشی از من سر زد، از من درگذر، عهد می‌بندم که از این پس، آن را تکرار نکرده و به چنین رفتاری باز نگردم». سپس بار دیگر جبرئیل نزد او آمده و به او گفت: «ای یعقوب (علیه السلام)! سرت را از خاک بردار»؛ زیرا پروردگار به تو سلام می‌رساند و می‌فرماید: «از تو درگذشتم، از این به بعد، شکوه به درگاه خلایق مبر و درد دلت را با بندگان در میان مگذار». بعد از آن هرگز دیده نشد که یعقوب (علیه السلام)، لب به چنین سخنانی بگشاید و زبان به گلایه باز کند و مصائب خویش را بیان کند. تا آن زمان که فرزندانش بدون بنیامین برگشتند؛ پس یعقوب (علیه السلام)، روی به دیوار کرده و چنین نالید: من غم و اندوهم را تنها به خدا می‌گویم [و شکایت نزد او می‌برم]! و از خدا چیزهایی می‌دانم که شما نمی‌دانید! (

یوسف/۸۶

).

... تَوَلَّی عَنْهُمْ وَ قَالَ یَا أَسَفَی عَلَی یُوسُفَ وَ ابْیَضَّتْ عَیْنَاهُ مِنَ الحُزْنِ یعنی چشمانش از شدّت گریه کور شده بود فَهُوَ کَظِیمٌ؛ یعنی غمگین بود و تأسف‌خوردن، منتهای اندوه است. از امام صادق (علیه السلام) سؤال شد: «یعقوب (علیه السلام) تا چه اندازه‌ای برای یوسف (علیه السلام)، غمگین شد»؟ فرمود: «به‌اندازه‌ی اندوه هفتاد زن که بچّه‌هایشان مرده باشند» و امام (علیه السلام) افزود: «یعقوب (علیه السلام)، استرجاع إِنَّا لِلهِ وَ إِنَّا إِلَیْهِ راجِعُونَ (

بقره/۱۵۶

) را نمی‌شناخت و به‌همین‌خاطر می‌گفت: یَا أَسَفَی عَلَی یُوسُفَ پس-ران به او گفتند: تَالله تَفْتَأُ تَذْکُرُ یُوسُفَ دست از ذکر نام یوسف (علیه السلام) و یاد او برنمی‌داری تا در آستانه‌ی مرگ قرار گیری. (

یوسف/۸۵

) یعنی بمیری من غم و اندوهم را تنها به خدا می‌گویم [و شکایت نزد او می‌برم]! و از خدا چیزهایی می‌دانم که شما نمی‌دانید! (

یوسف/۸۶

).

یعقوب (علیه السلام)، حزن او شدّت یافت یعنی که پشت او خمیده گشت. از سوی دیگر، دنیا چنان به یعقوب (علیه السلام) و فرزندانش پشت کرد که در وادی فقر و نیاز غلتیدند و هرآنچه از آذوقه داشتند، به انتها رسید. در این‌هنگام، یعقوب (علیه السلام) به پسرانش گفت: اذْهَبُواْ فَتَحَسَّسُواْ مِن یُوسُفَ وَ أَخِیهِ وَ لاَ تَیْأَسُواْ مِن رَّوْحِ الله إِنَّهُ لاَ یَیْأَسُ مِن رَّوْحِ الله إِلاَّ الْقَوْمُ الْکَافِرُونَ برخی از پسران یعقوب (علیه السلام) همراه با مقدار کمی کالا که یعقوب (علیه السلام) همراه آنان کرد، به‌سوی مصر روانه شدند. یعقوب (علیه السلام) نامه‌ای به عزیز مصر نوشت که آن را نیز به پسرانش سپرد تا با خود به مصر ببرند. یعقوب (علیه السلام) در این نامه، خواهان لطف و مهربانی و عطوفت عزیز مصر بر خویش و پسرانش شده بود. او به فرزندانش سفارش کرد که قبل از کالاها نامه را به عزیز مصر تحویل دهند. یعقوب (علیه السلام) در آن نامه، این چنین نوشته بود: بِسْمِ اللهِ الرَّحْمنِ الرَّحیمِ؛ خدمت عزیز مصر که آشکارکننده‌ی عدل و داد و برپادارنده‌ی میزان است. از یعقوب‌بن‌اسحاق بن‌ابراهیم خلیل الله (علیه السلام)، همان‌که در زمان نمرود می‌زیست و نمرود همان [پادشاهی] بود که هیزم بسیاری گرد آورد و آتش بزرگی برافروخت تا ابراهیم (علیه السلام) را در آتش بسوزاند؛ امّا خداوند، آتش را بر ابراهیم (علیه السلام)، گلستان کرد و او را از آن نجات بخشید. [ای عزیز مصر]! به پیشگاه تو بازگو می‌کنم که ما خانواده‌ای اصیل هستیم. همواره بلا از سوی خداوند، شتابناک به‌سوی ما می‌رسد تا خداوند، بدین‌سان ما را در آسایش و دشواری بیازماید. بیست سال است که مصیبت‌های روزگار، پی‌درپی و متوالی بر من فرود می‌آید. نخستین مصیبت درباره‌ی پسرم بود. پسری داشتم که او را یوسف (علیه السلام) نامیدم. او مایه‌ی شادمانی و سُرور من و نور چشم و میوه‌ی دلم بود. برادران ناتنی او از من خواستند که او را برای بازی و گردش در صحرا همراه آنان بفرستم. صبح هنگام، او را با آنان روانه کردم. امّا شامگاهان، برادران نزد من آمده و می‌گریستند. آنان پیراهن او را به دروغ به خون آغشته کرده و پیش من آوردند و ادّعا می‌کردند که گرگ، یوسف را دریده است. دوری او بر من، سخت گران آمد و در فراق او چنان گریستم که بینایی چشمانم از دست رفت. یوسف (علیه السلام)، برادری داشت از خاله‌اش که من او را سخت دوست می‌داشتم و همدم و همراه و مونس تنهایی‌هایم بود. چون یوسف (علیه السلام) در خاطرم می‌آم-د، او را به سینه‌ام می‌فشردم تا زخمی که در سینه‌ام بود، اندکی آرام گیرد. ای عزیز مصر! برادرانش برای من خبر آورده‌اند که تو از ایشان، درباره‌ی این برادرشان پرسیده‌ای و به آنان فرمان داده‌ای تا او را به نزد تو آورند و تهدید کرده‌ای که اگر او را به پیشگاه تو نیاورند، ما را از آذوقه که همان گندم سرزمین مصر است، محروم خواهی ساخت. پس او را با ایشان راهی کردم تا برایمان گندم و آذوقه بیاورند. امّا ایشان بازگشتند، بی‌آنکه او آنان را همراهی کند. به من گفتند که او پیمانه‌ی شاهی را به سرقت برده است. ما از خانواده‌ای هستیم که دزدی در خصلت و مرام ما نیست؛ امّا تو او را به جرم دزدی به حبس انداختی و یک‌باره مرا به فراق دردناک او مبتلا ساختی. از مصیبت فراق او چنان زخمی بر سینه‌ام نشست که پشتم خمیده شده و بار اندوه و مصیبت من، سخت گران آمده؛ چراکه این بلاها پی‌درپی بر من فرود آمدند. پس منّت بر من تمام کن و او را از حبس خویش، بیرون آور و راه او را باز کن و برایمان گندمی نیکو بفرست و در قیمت، مدارا کن و در راهی‌کردن آل‌یعقوب شتاب گیر». زمانی‌که پسران یعقوب (علیه السلام) به همراه نامه‌ی او به سمت مصر می‌رفتند، جبرئیل بر یعقوب (علیه السلام) فرود آمد و به او گفت: «ای یعقوب (علیه السلام)! پروردگارت به تو چنین می‌گوید: چه کسی تو را به مصیبت‌هایی که با عزیز مصر در میان نهادی، مبتلا ساخته است»؟ یعقوب (علیه السلام) گفت: «پروردگارا! این تو بودی که برای مجازات و تأدیب من، مرا به وادی بلا مبتلا ساختی». خداوند فرمود: «آیا جز من کسی می‌تواند این بلایا را از تو برگیرد»؟ یعقوب (علیه السلام) گفت: «خیر، ای پروردگار»! پروردگار فرمود: «از من شرم نکردی که زخم‌ها و دردهایت را با کسی غیر از من در میان نهادی و درد و اندوه خویش را به پیشگاه من نیاوردی و از من دادخواهی نکردی»؟! یعقوب (علیه السلام) گفت: «پروردگارا، از تو طلب مغفرت نموده و به درگاهت توبه می‌آورم و غم و اندوه خویش را در پیشگاه تو از سینه بیرون می‌ریزم». خداوند تبارک‌وتعالی فرمود: «ای یعقوب (علیه السلام)! تو و فرزندان خطاکارت را نهایتِ ادب کرده‌ام. اگر مصیبت‌ها و نگون‌بختی‌هایی که در تقدیر تو آمد، با من در میان می‌گذاشتی و طلب بخشش و استغفار می‌کردی و از گناهت توبه می‌نمودی، من آن مصائبی که در پیشانی‌نوشت تو نگاشته بودم، از صفحه‌ی تقدیر تو برمی‌گرفتم. امّا شیطان، یاد مرا از خاطر تو برد و تو مرا فراموش کردی و از رحمت من ناامید گشتی و حال آنکه من همان خداوند بسیار بخشنده و کریم هستم و آن گروه از بندگانی را دوست می‌دارم که به درگاه من توبه می‌آورند و به استغفار می‌نشینند و به آنچه نزد من است چشم انتظارند. ای یعقوب (علیه السلام)! من یوسف (علیه السلام) و برادرش را به تو باز خواهم گرداند؛ مال و گوشت و خونی که از دست تو رفته است را به تو باز پس خواهم داد؛ نور چشمانت را دوباره به تو خواهم داد و خمیدگی پشت تو را نیز راست خواهم کرد، پس شادمان باش و چشم خویش، روشن بدار که آنچه با تو کردم به‌جهت آن بود که تو را ادب کنم؛ پس ادب مرا بپذیر». امام فرمود: «پسران یعقوب (علیه السلام) همراه با نامه‌ی پدر به‌سوی مصر روانه شدند. هنگامی‌که به کاخ پادشاهی رسیدند و هنگامی‌که آن‌ها بر او (یوسف) وارد شدند، گفتند: «ای عزیز [مصر]! ما و خاندان ما را پریشانی [و قحطی] فراگرفته، و بهای اندکی [برای تهیّه‌ی موادّ غذایی] با خود آورده‌ایم؛ پیمانه را برای ما کامل کن؛ و بر ما تصدّق و بخشش نما. (

یوسف/۸۸

). درباره‌ی برادرمان بنیامین، و این نیز نامه‌ی پدرمان یعقوب (علیه السلام) است که درباره‌ی برادرمان بنیامین با تو سخن گفته و از تو درخواس-ت کرده تا بر او منّ-ت نهی و راه بنی-امین را باز کرده و او را از حبس بیرون کنی». امام (علیه السلام) فرمود: «یوسف (علیه السلام)، نامه‌ی پدرش یعقوب (علیه السلام) را گرفته و آن را بوسید و بر چشمانش نهاد و چنان گریست و نوحه کرد که پیراهنی که بر تن داشت از اشک‌های او خیس شد. آنگاه، به پیش برادران آمد و به آنان گفت: آیا دانستید با یوسف و برادرش چه کردید. (

یوسف/۸۹

) پیش از این و پس از وی»؟ گفتند: «آیا تو همان یوسفی»؟! گفت: «[آری] من یوسفم، و این برادر من است! خداوند بر ما منّت گذارد هرکس تقوا پیشه کند، و شکیبایی و استقامت نماید، [سرانجام پیروز می‌شود] چراکه خداوند پاداش نیکوکاران را ضایع نمی‌کند»! گفتند: «به خدا سوگند، خداوند تو را بر ما برتری بخشیده است. (

یوسف/۹۱-۹۰

) پس ما را رسوا مکن و از مجازات کنونی ما درگذر و گناهان ما را ببخشای. [یوسف] گفت: «امروز ملامت و توبیخی بر شما نیست! خداوند شما را می‌بخشد». (

یوسف/۹۲

).

از امام جواد (علیه السلام) روایت است: شنیدم پدرم از امام کاظم (علیه السلام) روایت فرمود: عمروبن‌عبید خدمت امام صادق (علیه السلام) رسید، و چون سلام کرد و نشست، گفت: «من می‌خواهم گناهان کبیره را از روی قرآنِ خدا عزّوجلّ بشناسم»، امام فرمود: «آری، ای عمرو! بزرگ‌ترین گناهان کبیره؛ ش-رک به خدا اس-ت، خدا می‌فرم-اید: زیرا هرکس شریکی برای خدا قرار ده-د، خداوند بهشت را بر او حرام کرده است. (

مائده/۷۲

) و پس از آن نومیدی از رحمت خدا است، زیرا خدای عزّوجلّ می‌فرماید: إِنَّهُ لا یَیْأَسُ مِنْ رَوْحِ الله إِلَّا الْقَوْمُ الْکافِرُونَ».

هیچ‌کس نباید از عذاب خدا ایمن باشد حتّی بهترین افراد این امّت که خداوند می‌فرماید: جز زیانکاران، خود را از مکر [و مجازات] خدا ایمن نمی‌دانند!. (

اعراف/۹۹

) و هیچ‌کس نباید از لطف و رحمت حقّ مأیوس و ناامید باشد حتی بدترین افراد این امّت که خداوند فرمود: لایَیْأَسُ مِنْ رَوْحِ الله إِلَّا الْقَوْمُ الْکافِرُونَ.

عزیز مصر به یعقوب (علیه السلام) نامه نوشت: «امّا بعد؛ پسرت یوسف (علیه السلام) را به بهایی ناچیز، چند درهم، خریداری کرده و او را به بردگی گرفته‌ام و بنیامین، دیگر فرزندت؛ را نیز که دزدی کرده به بردگی من درآمده است». یعقوب (علیه السلام)، پیش از آن، هرگز چنین ضربه‌ی روحی را تجربه نکرده بود. محتوای نامه، برای او بسیارگران بود؛ بنابراین به پیکی که نامه را آورده بود گفت: «اینجا بمان تا پاسخ نامه را بنویسم». یعقوب (علیه السلام) در پاسخ به عزیز مصر نوشت: «بِسْمِ اللهِ الرَّحْمنِ الرَّحیم؛ از یعقوب (علیه السلام)، اسرائیل الله (بنده‌ی خالص خدا)، فرزند اسحاق‌بن‌ابراهیم خلیل الله (علیه السلام) به عزیز مصر. امّا بعد؛ از محتوای نامه چنین برمی‌آمد که پسر مرا خریداری کرده و او را به بردگی گرفته‌ای. گریزی نیست؛ چراکه بلادیدگی، تقدیر آدمیان است. نیای من، ابراهیم (علیه السلام) نیز توسط پادشاه آن روز، به آتش درافتاد؛ امّا نسوخت و خداوند، آتش را بر او گلستان کرد. خداوند به جدّم ابراهیم (علیه السلام) فرمان داد که پدرم اسحاق پیامبر (علیه السلام) را با دستان خود ذبح کند و همین‌که خواست او را ذبح کند، خداوند، قوچ بزرگی را فدیه‌ی او قرار داد. من نیز پسری داشتم که مرا در این دنیا، کسی عزیزتر از او نبود؛ نور چشم و میوه‌ی دل من بود. برادرانش او را از من گرفته و با خود بردند و وقتی نزد من برگشتند، چنین ادّعا کردند که او را گرگ خورده است. از این خبر، پشتم خم شد و تا بدانجا گریه کردم که سوی چشمانم رفت و نابینا شدم. او برادری از طرف مادر داشت که بعد از وی، مونس من بود. او همراه با دیگر برادران به‌سوی سرزمین تو آمدند تا غذا و آذوقه‌ای برای ما بیاورند. برادران برگشتند و چنین ادّعا نمودند که وی پیمانه‌ی شاه را دزدیده است، و تو، او را زندانی کرده‌ای. ما از خانواده‌ای هستیم که دزدی و زشتی در شأن ما نیست و بر ما صدق نمی‌کند. من تو را به خدای ابراهیم و اسحاق و یعقوب (قسم می‌دهم که بر من منّت گذاری و به خاطر رضای خدا، او را آزاد کرده و به من بازگردانی». وقتی جواب نامه‌ی یعقوب (علیه السلام) به یوسف (علیه السلام) رسید، آن را برگرفته و بر روی چهره نهاد و بوسید و سخت گریست. سپس به برادران نگاه کرد و گفت: آیا دانستید آنگاه که جاهل بودید با یوسف و برادرش چه کردید؟ گفتند: «آیا تو همان یوسفی»؟! گفت: «[آری]، من یوسفم، و این برادر من است! خداوند بر ما منّت گذارد هرکس تقوا پیشه کند، و شکیبایی و استقامت نماید، [سرانجام پیروز می‌شود] چراکه خداوند پاداش نیکوکاران را ضایع نمی‌کند»!. (

یوسف/۹۰-۸۹

) بنا به فرموده‌ی پروردگار، برادران به یوسف (علیه السلام) گفتند: «به خدا سوگند، خداوند تو را بر ما برتری بخشیده و ما خطاکار بودیم»!. [یوسف] گفت: «امروز ملامت و توبیخی بر شما نیست»!. (

یوسف/۹۲-۹۱

) یعنی ملامت و سرزنشی بر شما نیست، خداوند شما را می‌بخشد و او مهربان‌ترین مهربانان است!. (

یوسف/۹۲

) وقتی فرستاده‌ی یوسف (علیه السلام) همراه با نامه‌ی یعقوب (علیه السلام) به‌سوی وی روانه گشت، یعقوب (علیه السلام) دو دستش را به‌سوی آسمان، فراز کرده و گفت: ای که همدمی با تو نیکوست و یاری‌ات بزرگوارانه! ای بهترین سخن! گشایش و آرامش را از جانب خویش بر من ارزانی دار. دراین‌هنگام، جبرئیل بر او نازل شد و گفت: «ای یعقوب (علیه السلام)! دوست داری به تو دعاهایی را بیاموزم که با این دعاها خداوند، بینایی تو را به تو باز پس دهد و دو پسرت را نیز به تو بازگرداند»؟ گفت: «آری». جبرئیل گفت: «پس این چنین بگوی: «ای خدایی که جز خودش کسی نمی‌داند که وی چگونه است! ای آن که هوا را با آسمان، مسدود ساخته و زمین را با آب انباشت و بهترین نام‌ها را برای خویش برگزید! از جانب خودت آسایش و گشایشی به من ارزانی دار». امام (علیه السلام) فرمود: «هنوز سپیده‌ی صبح ندمیده و همه جا را فرا نگرفته بود که پیراهن یوسف (علیه السلام) بر روی صورت او افکنده شد و خداوند متعال بینایی او را به او باز پس داد و پسرانش را نیز به وی بازگرداند». امام (علیه السلام) فرمود: «هنگامی‌که پادشاه مصر دستور داد که یوسف (علیه السلام) در زندان محبوس شود، خداوند، تعبیر خواب را به وی الهام فرمود؛ بنابراین یوسف (علیه السلام)، خواب زندانیان را تأویل می‌کرد و وقتی آن دو جوان تعبیر و تفسیر خواب خویش را از یوسف (علیه السلام) خواستند، یوسف (علیه السلام)، خواب آنان را تفسیر کرد و به آنکه فکر می‌کرد از زندان رهایی می‌یابد، گفت: مرا نزد صاحبت [سلطان مصر] یادآوری کن. (

یوسف/۴۲

) و در آن شرایط به درگاه خداوند، تضرّع نکرد و خداوند به او وحی کرد: «چه کسی آن خواب را به تو نمایاند»؟ یوسف (علیه السلام) عرض کرد: «تو ای خدای من»! پروردگار فرمود: «چه کسی تو را عزیز پدر و نزد او بسیار محب-وب نمود»؟ عرض کرد: «تو ای خ-دای من»! پروردگ-ار فرمود: «چه کسی آن کاروان را که دیدی، به‌سوی تو روانه کرد»؟ عرض کرد: «تو ای پروردگار من»! فرمود: «چه کسی آن دعا را به تو آموخت تا با آن تو را از آن چاه بیرون کشیده و رهایی داد»؟ عرض کرد: «تو ای خدای من»! فرمود: «چه کسی آن کودک را به سخن درآورد تا بی‌گناهی تو را ثابت کند»؟ عرض کرد: «تو ای خدای من»! فرمود: «چه کسی تفسیر خواب را به تو الهام کرد»؟ عرض کرد: «تو ای خدای من»! فرمود: «چگونه جسارت کردی و از غیر من یاری جستی و از من استعانت نخواستی؟ امید به بنده‌ای از بندگانم بستی تا تو را نزد یکی از آفریده‌های من که در چنگ قدرت من، اسیر است، یاد کند و به درگاه من تضرّع نکردی و پریشان خاطری خویش را برای من بازگو نکردی؛ پس چند سال در زندان درنگ کن». یوسف (علیه السلام) گفت: «پروردگارا! تو را به حقّ همه‌ی پدرانم قسم داده و از درگاهت مسئلت دارم که در کار من، گشایش آوری». خداوند به یوسف (علیه السلام) وحی کرد: «یوسف! پدران تو چه حقّی بر من دارند؟ اگر منظورت از پدرانت آدم (علیه السلام) است، که خود با دستانم او را آفریدم و از روح و جان خود در او دمیدم و او را در بهشت خویش سکونت دادم و از او خواستم که به آن درخت نزدیک نشود؛ امّا وی از فرمان من سرپیچی کرد و سپس بازگشت و توبه نمود. من نیز توبه‌اش را پذیرفتم. اگر مقصود از پدرانت، نوح (علیه السلام) است، من خود وی را از میان بندگان و مخلوقاتم برگزیدم و او را فرستاده‌ی خود به‌سوی آنان قرار دادم و هنگامی‌که مردم از او سرپیچیدند، به درگاه من دعا کرد و من عصیانگران را غرق کردم و نوح (علیه السلام) و کسانی که با او در کشتی بودند را نجات دادم. اگر مقصودت از پدرانت ابراهیم (علیه السلام) است، من خود، او را دوست و خلیل خویش برگرفتم و از آتش رهانیدم و آن را بر او گلستان کردم. اگر مقصود از پدرانت، یعقوب (علیه السلام) است، من به او دوازده پسر دادم و یکی از آن‌ها را از او دور کردم. وی پیوسته گریست تا آنکه بیناییش را از دست داد. او بر سر راه می‌نشست و شکایت مرا به پیشگاه خلق می‌برد و با مردمان درد دل می‌کرد. با این اوصاف، پدران تو چه حقّی بر من دارند؟ امام (علیه السلام) فرمود: «جبرئیل به یوسف (علیه السلام) گفت: ای یوسف! بگو: پروردگارا! من از تو، از لطف و مرحمت سرشار و عظیمت و از احسان قدیمت و از لطف و عنایت فراگیرت، ای رحمان و ای رحیم! درخواست آسایش و گشایش می‌کنم. پس یوسف (علیه السلام) این جملات را گفت و پادشاه نیز آن خواب را دید و گشایش کار یوسف (علیه السلام) در همان خواب بود.

إِنَّمَا التَّوْبَةُ عَلَی الله لِلَّذِینَ یَعْمَلُونَ السُّوءَ بِجَهالَةٍ (

نساء/۱۷

) یعنی هر گناهی که بنده‌ای مرتکب می‌شود هرچند که بداند گناه است باز هم جاهل است، چون خودش را در نافرمانی پروردگارش به خطر انداخته، چنانکه در این رابطه خدای تبارک‌وتعالی کلام یوسف (علیه السلام) را حکایت می‌کند که به برادرانش گفت: هَلْ عَلِمْتُمْ ما فَعَلْتُمْ بِیُوسُفَ وَ أَخِیهِ إِذْ أَنْتُمْ جاهِلُونَ به آنان نسبت جهل داد چراکه خود را در نافرمانی پروردگارشان به خطر انداختند.

مردی بر حضرت صادق (علیه السلام) وارد شد. حضرت فرمود: «این مرد از کدام دسته است»؟ عرض کرد: «از دوستان و وابستگان شما». ... حضرت فرمود: «چنین مردمی نشانه‌هایی دارند که بدان شناخته شوند.» آن مرد پرسید: «چیست آن نشانه‌ها؟» فرمود: «آن نشانه‌ها، صفات برجسته‌ای است که اوّل آنها این است که یگانگی خدا را چنانچه باید شناختند و دانش توحید او را استوار کردند. پس از آن، ایمان را چنانچه باید، با اوصافش و سپس حدود و حقایق و شرایط و تأویل ایمان را دانسته‌اند.» سدیر گفت: «ای پسر پیامبر (صلی الله علیه و آله)! تا به حال نشنیده بودم که ایمان را چنین ستوده باشی.» فرمود: «آری ای سدیر! کسی را نشاید که پرسد ایمان چیست تا بداند که ایمان که راشاید.» سدیر گفت: «ای پسر پیامبر (صلی الله علیه و آله)! اگر موافق باشید، آنچه را که فرمودید شرح دهید.» حضرت فرمود: «کسی که گمان کند خدا را می‌شناسد، از راه خیال‌بافی در دلش مشرک است. کسی که پندارد خدا را به نام و بدون معنی شناخته، به نقص خدا اقرار کرده، زیرا اسم پدیده است [و دوام و بقایی ندارد]. هر کس که پندارد نام و معنی را می‌پرستد، برای خدا شریک قرار داده است. هر کس پندارد که معنا رامی‌پرستد، به وصفی که آن را درک نمی‌کند، چیزی را اراده کرده که از ذهن او غایب است. هر کس پندارد که صفت و موصوف را می‌پرستد، توحید را نابود ساخته، زیرا صفت غیر موصوف است. هر کس که پندارد موصوف را به صفت نسبت می‌دهد، بزرگ را کوچک ساخته و چنانچه بایست، اندازه و میزان خدا را رعایت نکرده است.» کسی پرسید: «پس راه توحید چگونه است؟» فرمود: «درِ کاوش باز است و راه گشایش شبهات موجود. همانا شناخت ذات حاضر، پیش از وصف اوست و شناخت وصفِ نادیده، پیش از ذات او.» گفتند: «چگونه می‌شناسی ذات حاضر را پیش از وصف او؟» فرمود: «او را می‌شناسی و می‌دانی و خود را بدو می‌شناسی، و خویشتن را به خویش و به راهنمایی خود نمی‌شناسی، و می‌دانی آنچه را که در اوست، برای او و مخصوص اوست. چنانچه برادران یوسف بدو گفتند: «إِنَّکَ لَأَنْتَ یُوسُفُ قالَ أَنَا یُوسُفُ وَ هذا أَخِی، یوسف (علیه السلام) را به خودش شناختند و او را به غیر او نشناختند و از پیش خود، به خیال دل چیزی نساختند. آیا نبینی که خداوند می‌فرماید: ما کانَ لَکُمْ أَنْ تُنْبِتُوا شَجَرَها؛ شما هرگز قدرت نداشتید درختان آن را برویانید! (

نمل/۶۰

) می‌فرماید، شما را نرسد که از پیش خود امامی وادارید و آن را به خواهش دل و خواست خود بر حق شمارید.» سپس حضرت صادق (علیه السلام) فرمود: «سه نفرند که روز قیامت خدا با آنان سخن نگوید، بدانها ننگرد و پاکشان نسازد و عذابی دردناک دارند [و آنها عبارتند از:] کسی که درختی را بنشاند که خدایش نرویاند، یعنی پیشوایی را وادارد که خدا برنیانگیخته است؛ کسی که برانگیخته خدا را انکار کند؛.. و خداوند می‌فرماید: پروردگار تو هر چه بخواهد می‌آفریند، و هر چه بخواهد برمی‌گزیند آنان (در برابر او) اختیاری ندارند (

قصص/۶۸

)».

اسماعیل‌بن‌فضل‌هاشمی گوید: محضر امام صادق (علیه السلام) عرض کردم: مرا از یعقوب (علیه السلام) که وقتی فرزندانش به او عرض کردند: پدر! از خدا آمرزش گناهان ما را بخواه، که ما خطاکار بودیم!. (

یوسف/۹۷

) خبردهید که چرا به ایشان فرمود: به‌زودی برای شما از پروردگارم آمرزش می‌طلبم. (

یوسف/۹۸

) یعنی چرا طلب آمرزش را تأخیر انداخت و فوراً آن‌ها را نبخشید. و نیز وقتی برادران یوسف (علیه السلام) به حضرتش عرضه داشتند: تَالله لَقَدْ آثَرَکَ الله وَ إِنْ کُنَّا لَخاطِئِینَ چرا جناب یوسف (علیه السلام) فرمود: امروز ملامت و توبیخی بر شما نیست! خداوند شما را می‌بخشد و او مهربان‌ترین مهربانان است! (

یوسف/۹۲

) پس بدون درنگ از خطای آن‌ها درگذشت و آن را به تأخیر نیانداخت»؟ امام (علیه السلام) فرمود: «دلیلش آن است که قلب جوان نازک‌تر از قلب پیر است؛ از این‌رو یوسف (علیه السلام) بدون درنگ از خطای برادرانش گذشت؛ ولی یعقوب (علیه السلام) عفو و گذشت را به تأخیر انداخت. و نیز برادران یوسف (علیه السلام) نسبت به یوسف (علیه السلام) مستقیماً جنایت کردند ولی در حقّ یعقوب (علیه السلام) جنایتشان به خاطر جنایت بر یوسف (علیه السلام) بوده لاجرم یوسف (علیه السلام) نسبت به حقّ خودش مبادرت به عفو نمود، امّا یعقوب (علیه السلام) چون گذشتش در واقع عفو از حقّ غیر بوده نه از حقّ خود، به ناچار آن را تا سحر شب جمعه تأخیر انداخت و این امر طبیعی است که انسان از حقّ خود به سرعت می‌تواند بگذرد امّا درباره‌ی حقّ دیگری جای تأخیر دارد».

سه آیه در مورد پیراهن یوسف (علیه السلام) وجود دارد: و پیراهن او را با خونی دروغین (آغشته ساخته، نزد پدر) آوردند (

یوسف/۱۸

) و اگر پیراهن او از پیش رو پاره شد (

یوسف/۲۶

) ... و این کلام خداوند: اذْهَبُوا بِقَمِیصِی هَذَا.

مفضّل‌بن‌عمر گوید: از امام صادق (علیه السلام) شنیدم که فرمود: «می‌دانی پیراهن یوسف (علیه السلام) چه بود»؟ عرض کردم: «نه». فرمود: «وقتی برای [سوزاندن] ابراهیم (علیه السلام) آتش افروختند، جبرئیل جامه‌ای از جامه‌های بهشت برایش آورده و به او پوشانید و با آن جامه، گرما و سرما به ابراهیم (علیه السلام) زیانی نمی‌رسانید. زمان مرگ ابراهیم (علیه السلام) فرا رسید، آن را در غلافی نهاد و به اسحاق (علیه السلام) و اسحاق (علیه السلام) آن را به یعقوب (علیه السلام) و چون یوسف (علیه السلام) به دنیا آمد، یعقوب (علیه السلام) آن را بر او آویخت و پیوسته در بازوی او بود تا زمانی‌که آن جریانات برای یوسف (علیه السلام) اتّفاق افتاد. هنگامی‌که یوسف (علیه السلام) پیراهن را در مصر از غلاف بیرون آورد، یعقوب (علیه السلام) بوی آن را [در کنعان] احساس کرد؛ چنانکه در قرآن می‌فرماید: من بوی یوسف را احساس می‌کنم، اگر مرا به نادانی و کم عقلی نسبت ندهید!. (

یوسف/۹۴

). و آن همان پیراهنی بود که خداوند از بهش-ت فرو فرستاده بود. عرض کردم: «فدایت شوم! در نهایت، آن پیراهن به چه کسی رسید»؟ امام (علیه السلام) فرمود: «به اهلش رسید»، آنگاه فرمود: «هر پیغمبری که دانش یا چیز دیگری را به ارث برده، در نهایت به آل‌محمّد (رسیده است. و هنگامی‌که کاروان از سرزمین مصر به راه افتاد یعقوب (علیه السلام) در فلسطین بود که بوی یوسف (علیه السلام) را احساس کرد و آن بوی همان پیراهنی بود که از بهشت آورده شده بود؛ و ما (اهل بیت) آن را به ارث برده‌ایم».

[یوسف] گفت: «امروز ملامت و توبیخی بر شما نیست! خداوند شما را می‌بخشد و او مهربان‌ترین مهربانان است!. (

یوسف/۹۲

) اذْهَبُوا بِقَمِیصِی هذا پیراهنی که با اشک چشمانم خیس شده است را ببرید و فَأَلْقُوهُ عَلی وَجْهِ أَبِی یَرْتَدَّ بَصِیراً؛ اگر بوی مرا از آن استشمام کند وَ أْتُونِی بِأَهْلِکُمْ أَجْمَعِینَ. سپس یوسف (علیه السلام) همان روز، همگی آن‌ها را به‌سوی یعقوب (علیه السلام) روانه کرد و هرآنچه که به آن نیاز داشتند را به آنان داد و هنگامی‌که کاروان آن‌ها از مصر بیرون آمد و حرکت کرد، یعقوب (علیه السلام) گفت: «من بوی یوسف (علیه السلام) را احساس می‌کنم. پس به آنان که در حضور او بودند». گفت: من بوی یوسف را احساس می‌کنم، اگر مرا به نادانی و کم عقلی نسبت ندهید!. (

یوسف/۹۴

) پسران یعقوب (علیه السلام) با شادمانی و سرور و سرخوش از منزلت یوسف (علیه السلام) و پادشاهی - که خداوند به وی عطا کرده بود - و شادمان از عزّت و منزلتی که در درگاه یوسف (علیه السلام) دیده بودند، پیراهن یوسف (علیه السلام) را شتابان به‌سوی یعقوب (علیه السلام) بردند. از مصر تا سرزمین یعقوب (علیه السلام) نه روز راه بود. زمانی‌که مژده رسیدن پسران آمد و در پی آن، کاروانیان وارد شدند، پیراهن یوسف (علیه السلام) را بر روی یعقوب (علیه السلام) انداختند. بینایی به چشمان یعقوب (علیه السلام) باز آمد. یعقوب (علیه السلام) از پسرانش پرسید: «با بنیامین چه کردید»؟ گفتند: «او را نزد برادر صالح و شایسته‌ی او یعنی یوسف (علیه السلام) گذاشتیم». امام (علیه السلام) فرمود: «سپس یعقوب (علیه السلام) شکر خداوند متعال را به جا آورد و به درگاه ذات حق سجده‌ی شکر کرد. بینایی‌اش به او بازگشت و خمیدگی پشتش نیز راست شد و به فرزندانش گفت: همین امروز، همگی شما بار سفر به‌سوی یوسف (علیه السلام) برببندید. پس همگی آن‌ها همراه با یعقوب (علیه السلام) و «یامیل» خاله یوسف (علیه السلام) به‌سوی یوسف (علیه السلام) حرکت کردند. آنان با شادمانی و خوشحالی به‌سوی مصر شتاب کردند و نه روز بعد در مصر بودند».

فردی صحرانشین، نزد یوسف (علیه السلام) آمد که از وی مقداری غذا بخرد؛ یوسف (علیه السلام) به او فروخت و وقتی از این کار، فارغ شد به او گفت: «خانه‌ات کجاست»؟ پاسخ داد: «در فلان جا». یوسف (علیه السلام) به او گفت: «اگر گذرت به دشت فلان افتاد، بایست و بانگ برآور و بگو: «ای یعقوب (علیه السلام)! ای یعقوب (علیه السلام)»! خواهی دید که مردی تنومند، خوش‌سیما و زیباروی، نزد تو خواهد آمد؛ به او بگو: «با مردی در مصر برخورد کردم که به تو سلام رساند و این پیغام را برای تو داشت. امانتی که نزد خدای متعال گذاشته‌ای، هرگز تباه نخواهد شد». حضرت (علیه السلام) فرمود: «آن مرد بیابان‌نشین رفت و به آنجا که یوسف (علیه السلام) گفته بود، رسید و به غلامانش اشاره کرد که مواظب باشید که مبادا از شتر فرو افتم؛ سپس فریاد برآورد و گفت: ای یعقوب (علیه السلام)! ای یعقوب (علیه السلام)! پس دید مردی نابینا، بلندقامت، درشت هیکل و زیباروی، دست به دیوار گرفته به‌سوی او می‌آید؛ چون به او رسید، آن مرد به او گفت: «تو یعقوب (علیه السلام) هستی»؟ گفت: «آری منم». آن مرد، پیغام یوسف (علیه السلام) را به یعقوب (علیه السلام) داد. یعقوب از هوش رفت و بر زمین افتاد. وقتی که به هوش آمد به اعرابی گفت: «ای اعرابی! آیا حاجت و تمنّایی از خداوند متعال داری»؟ گفت: «آری. من مردی ثروتمند هستم و دختر عمویی دارم که از من، صاحب فرزند نمی‌شود؛ خوش می‌دارم که از خداوند بخواهی تا به من فرزندی عطا کند». امام (علیه السلام) فرمود: «یعقوب (علیه السلام) وضو ساخت و دو رکعت نماز گزارد و سپس به درگاه خداوند متعال دعا کرد و آن مرد، چهار بار صاحب فرزند ش-د، یا اینکه فرمود: شش بار صاحب فرزند شد که همسرش هر بار، دوقلو می‌زایید. یعقوب (علیه السلام) می‌دانست یوسف (علیه السلام)، زنده است و نمرده است و خداوند متعال به او یادآوری کرده بود که بعد از این غیبت، روی او را آشکار خواهد نمود و به پسرانش می‌گفت: من از خدا چیزهایی می‌دانم که شما نمی‌دانید؟!. (

یوسف/۹۶

) این درحالی بود که فرزندان و خویشاوندان و نزدیکانش او را به خاطر آنکه بسیار از یوسف (علیه السلام)، یاد می‌کرد، ملامت می‌کردند، تا آنکه او بوی یوسف (علیه السلام) را احساس کرد و گفت: إِنِّی لَأَجِدُ رِیحَ یُوسُفَ لَوْلاَ أَن تُفَنِّدُونِ* قَالُواْ تَالله إِنَّکَ لَفِی ضَلاَلِکَ الْقَدِیمِ* فَلَمَّا أَنْ جاءَ الْبَشیرُ أَلْقاهُ عَلی وَجْهِهِ فَارْتَدَّ بَصیراً قالَ أَ لَمْ أَقُلْ لَکُمْ إِنِّی أَعْلَمُ مِنَ اللهِ ما لا تَعْلَمُونَ (

یوسف/۹۴-۹۶

).

یوسف (علیه السلام) به برادرانش گفت: امروز ملامت و توبیخی بر شما نیست! خداوند شما را می‌بخشد. (

یوسف/۹۲

) اذْهَبُوا بِقَمِیصِی هذا، این پیراهن مرا که اشک دیدگانم آن را مرطوب نموده ببرید فَأَلْقُوهُ عَلی وَجْهِ أَبِی یَرْتَدَّ بَصِیراً و بر صورت پدرم بیندازید، اگر بوی مرا استشمام نماید بینا می‌شود. و همه‌ی نزدیکان خود را نزد من بیاورید!. (

یوسف/۹۳

). یوسف (علیه السلام) در همان روز ایشان را به آنچه نیازمند آن بودند مجهّز نمود و به‌سوی یعقوب (علیه السلام) روانه کرد. وقتی کاروان از مصر دور شد، یعقوب (علیه السلام) بوی یوسف (علیه السلام) را شنید و به آن فرزندانی که نزدش بودند فرمود: من بوی یوسف را احساس می‌کنم، اگر مرا به نادانی و کم عقلی نسبت ندهید!. (

یوسف/۹۴

) امام باقر (علیه السلام) در ادامه فرمود: «از طرف دیگر فرزندانی که از مصر می‌آمدند، با شتاب می‌راندند تا پیراهن را زودتر برسانند، چراکه از دیدن حال و روز یوسف (علیه السلام) و سلطنتی که خدا به او عطا کرده بود بسیار شاد و مسرور بودند، چون می‌دیدند خود ایشان هم به خاطر سلطنت برادر، عزّتی پیدا کرده‌اند. و مسافتی که باید میان مصر و دیار یعقوب (علیه السلام) طی می‌کردند، نُه روز راه بود». فَلَمَّا أَنْ جاءَ الْبَشِیرُ هنگامی‌که بشارت‌دهنده [به نزد یعقوب (علیه السلام)] رسید، أَلْقاهُ عَلی وَجْهِهِ فَارْتَدَّ بَصیرا و از آن‌ها پرسید: «بنیامین چه شد»؟ گفتند: «او را نزد برادرش در سلامتِ کامل گذاشتیم». یعقوب (علیه السلام) دراین‌هنگام حمد الهی را به‌جای آورد و سجده شکر نمود؛ چشمانش بینا شد و خمیدگی پشتش راست گردید. آنگاه به فرزندانش دستور داد همان روز با تمامی خاندان به‌سوی یوسف (علیه السلام) حرکت کنند. آن‌ها نیز به همراه یعقوب (علیه السلام) و «یامیل» خاله‌ی یوسف (علیه السلام) حرکت کرده و از روی شادی و سروری که داشتند با شتاب می‌راندند، و پس از نُه روز به مصر رسیدند.

اسماعیل‌بن‌فضل‌هاشمی گوید: به امام صادق (علیه السلام) عرض کردم: «مرا از یعقوب (علیه السلام) که وقتی فرزندانش به او عرض کردند: پدر! از خدا آمرزش گناهان ما را بخواه، که ما خطاکار بودیم!. (

یوسف/۹۸

) خبر دهید که چرا به ایشان فرمود: سَوْفَ أَسْتَغْفِرُ لَکُمْ رَبِّی چرا طلب آمرزش را تأخیر انداخت و فوراً آن‌ها را نبخشید. و نیز وقتی برادران یوسف (علیه السلام) به حضرتش عرضه داشتند: «به خدا سوگند، خداوند تو را بر ما برتری بخشیده و ما خطاکار بودیم»! [یوسف] گفت: «امروز ملامت و توبیخی بر شما نیست! خداوند شما را می‌بخشد و او مهربان‌ترین مهربانان است!. (

یوسف/۹۲-۹۱

) چرا یوسف (علیه السلام) فرمود: «امروز ملامت و توبیخی بر شما نیست! خداوند شما را می‌بخشد و او مهربان‌ترین مهربانان است»!. (

یوسف/۹۲

) پس بدون درنگ از خطاء آن‌ها درگذشت و آن را به تعویق نیانداخت»؟ امام (علیه السلام) فرمود: دلیلش آن است که قلب جوان نازک‌تر از قلب پیر است؛ از این‌رو یوسف (علیه السلام) بدون درنگ از خطای برادرانش گذشت ولی یعقوب (علیه السلام) عفو و گذشت را به تأخیر انداخت. و نیز برادران یوسف (علیه السلام) نسبت به یوسف (علیه السلام) مستقیماً جنایت کردند ولی در حقّ یعقوب (علیه السلام) جنایتشان به خاطر جنایت بر یوسف (علیه السلام) بوده؛ لاجرم یوسف (علیه السلام) نسبت به حقّ خودش مبادرت به عفو نمود امّا یعقوب (علیه السلام) چون گذشتش در واقع عفو از حقّ غیر بوده نه از حقّ خود به ناچار آن را تا سحر شب جمعه تأخیر انداخت.

یحیی‌بن‌اکثم گوید: موسی‌بن‌محمّد در مورد موضوعاتی سؤال داشت که آن‌ها را به امام هادی (علیه السلام) عرضه کرد. یکی از آن‌ها این بود پیرامون آیه: وَ رَفَعَ أَبَوَیْهِ عَلَی الْعَرْشِ وَ خَرُّوا لَهُ سُجَّداً از امام هادی (علیه السلام) پرسید: «آیا یعقوب (علیه السلام) و فرزندانش با اینکه از پیامبران بودند برای یوسف (علیه السلام) سجده کردند»؟! امام (علیه السلام) در جواب فرمود: «سجده‌ی یعقوب (علیه السلام) و فرزندانش برای یوس-ف (علیه السلام) نبود بلکه سج-ده‌ی ایشان، به‌عنوان عبادت خدا و [درعین‌حال] تحیّت و درودی برای یوسف (علیه السلام) بود، همچنان که فرشتگان در مقابل آدم (علیه السلام) سجده کردند ولی این سجده به خاطر او نبود بلکه به‌عنوان طاعت خدا بود و تحیّتی برای آدم (علیه السلام). یعقوب (علیه السلام) و فرزندانش و خود یوسف (علیه السلام) همه به‌عنوان شکر الهی، برای خدا سجده کردند چراکه خداوند، آن‌ها را گرد هم جمع نموده بود، مگر نمی‌بینی که یوسف (علیه السلام) در مقام شکر الهی عرض کرد: پروردگارا! بخشی [عظیم] از حکومت به من بخشیدی، و مرا از علم تعبیر خواب‌ها آگاه ساختی! ای آفریننده‌ی آسمان‌ها و زمین! تو ولیّ و سرپرست من در دنیا و آخرت هستی، مرا مسلمان بمیران و به صالحان ملحق فرما!. (

یوسف/۱۰۱

) دراین‌هنگام، جبرئیل بر یوسف (علیه السلام) نازل شد و خطاب به او گفت: «ای یوسف (علیه السلام)! دست خود را بیرون بیاور»، وقتی یوسف (علیه السلام) دست خود را بیرون آورد از میان انگشتانش نوری خارج گردید، یوسف (علیه السلام) گفت: «ای جبرئیل! این نور چه بود»؟ جبرئیل (علیه السلام) گفت: «این (نورِ) نبوّت است که خداوند آن را از نسل تو بیرون آورد، چراکه به احترام پدرت از جای خود برنخاستی». بدین‌ترتیب، خداوند نورش را زدوده و نبوّت را از نسل یوسف (علیه السلام) محو نمود و آن را در نسل لاوی برادر یوسف (علیه السلام) قرار داد و این بدان‌جهت بود که چون برادران، قصد کشتن یوسف (علیه السلام) را نمودند، لاوی گفت: یوسف را نکشید! و اگر می‌خواهید کاری انجام دهید، او را در نهانگاه چاه بیفکنید. (

یوسف/۱۰

) بدین‌خاطر خداوند از کار او تقدیر نمود؛ و زمانی هم که بنیامین به دستور یوسف (علیه السلام) در مصر نگه داشته شد و برادران قصد بازگشتن به نزد یعقوب (علیه السلام) راداشتند، لاوی گفت: من از این سرزمین حرکت نمی‌کنم، تا پدرم به من اجازه دهد یا خدا درباره‌ی من داوری کند، که او بهترین حکم‌کنندگان است! (

یوسف/۸۰

) بدین‌خاطر خداوند از کار او تقدیر نمود، در نتیجه همه‌ی پیامبرانِ بنی‌اسرائیل از فرزندان لاوی پسر یعقوب‌بن‌اسحاق بن‌ابراهیم (علیه السلام) بودند و موسی (علیه السلام) نیز از فرزندان او بود، بدین‌صورت که او موسی‌بن‌عمران بن‌یهصربن واهث‌بن‌لاوی بن‌یعقوب‌بن‌إسحاق بن‌ابراهیم (علیه السلام) می‌باشد.

محمّد گوید: از امام باقر (علیه السلام) پرسیدم: «یعقوب (علیه السلام) چند سال در مصر با یوسف (علیه السلام) زندگی نمود»؟ امام (علیه السلام) فرمود: «دو سال». پرسیدم: «در آن مدّت حجّت خدا بر روی زمین چه کسی بود، یعقوب (علیه السلام) یا یوسف (علیه السلام)»؟ فرمود: «یعقوب (علیه السلام) حجّت خدا بود و سلطنت، برای یوسف (علیه السلام) بود. هنگامی‌که یعقوب (علیه السلام) از دنیا رفت یوسف (علیه السلام) او را در تابوتی نهاده و به سرزمین شام آورد و در بیت المقدس دفن نمود و از آن پس، یوسف (علیه السلام) حجّت خدا بود. عرض کردم: «پس یوسف (علیه السلام) هم رسول بود هم نبیّ»؟ امام (علیه السلام) فرمود: «آری! آیا نشنیدی گه خداوند متعال فرمود: پیش از این یوسف دلایل روشن برای شما آورد. (

غافر/۳۴

)

از امام حسین (علیه السلام) روایت است: عالمی از یهودیان شام به امام علی (علیه السلام) گفت: این حضرت یوسف (علیه السلام) است که سختی دوری و فراق پدر چشید، و برای پرهیز از گناه گوشه زندان را برگزید، و تک و تنها در چاه انداخته شد. حضرت (علیه السلام) فرمود: همین طور است، و حضرت محمّد (صلی الله علیه و آله) سختی و مرارت غربت و فراق و دوری اهل و اولاد و مال را چشید، و از حرم امن الهی مهاجرت نمود، و هنگامی که خداوند این حال او را مشاهده فرمود، خوابی را همچون خواب یوسف به او نمایاند و راستی و صدق آن را برای جهانیان نمایاند و فرمود: خداوند آنچه را به پیامبرش در عالم خواب نشان داد راست گفت بطور قطع همه شما بخواست خدا وارد مسجد الحرام می‌شوید در نهایت امنیّت و درحالی‌که سرهای خود را تراشیده یا کوتاه کرده‌اید و از هیچ کس ترس و وحشتی ندارید ولی خداوند چیزهایی را می‌دانست که شما نمی‌دانستید [و در این تأخیر حکمتی بود] و قبل از آن، فتح نزدیکی [برای شما] قرار داده است. (

فتح/۲۷

) و اگر یوسف در زندان محبوس شد، رسول خدا (صلی الله علیه و آله) خود را در شعب ابی طالب به مدّت سه سال محبوس نمود، درحالی‌که تمام اقارب و فامیل با او قطع رابطه نمودند، و کفّار او را به شدّت در تنگنا قرار دادند. در این میان خداوند ضعیف‌ترین خلق خود را امر فرمود تا آن عهد مکتوب ایشان را در قطع رحم با آن حضرت بخورد. و اگر یوسف (علیه السلام) در چاه انداخته شد، حضرت محمّد (صلی الله علیه و آله) از ترس دشمنش در غار مخفی شد، تا اینکه به همراه خود فرمود: «غم مخور، خدا با ماست!» (

توبه/۴۰

) و خداوند با این کلام وی را در قرآن مدح فرموده است.

مسعده‌بن‌صدقه گوید: «سفیان ثوری خدمت امام صادق (علیه السلام) رسید و دید که ایشان لباس‌هایی سفید رنگ به روشنی پوسته سفید تخم‌مرغ پوشیده‌است. وی به امام عرض کرد: «چنین لباسی در شأن شما هست»؟! امام فرمود: «خوب گوش کن و آنچه را به تو می‌گویم به خاطر بسپار؛ چراکه هم برای اکنون تو خیر است و هم برای آینده‌ات، مشروط بر آنکه براساس حقّ و سنّت از دنیا بروی، نه بر پایه‌ی بدعت. بدان‌که رسول خدا (صلی الله علیه و آله) در دوران فقر و نداری زندگی می‌کردند، امّا اگر دنیا روی آورد و وضعیّت معیشت مردم بهبود یابد و دست‌ها گشاده گردد، شایسته‌ترین مردم برای لذّت‌بردن و بهره‌مندی از دنیا، نیکان هستند، نه بدکاران و فاجران. این حقّ مؤمنان است که از نعمت‌ها برخودار گردند، نه منافقان؛ بهره‌گرفتن از دنیا، شایسته‌ی مسلمانان است نه کافران. بنابراین ای ثوری! چه چیز را در من ناخوشایند یافتی؟ ... بدانید که من از پدرم شنیدم که از پدرانش روایت می‌کرد که حضرت محمّد (صلی الله علیه و آله) فرمود: من از هیچ چیز به‌اندازه‌ی کار مؤمن و شأن او در شگفت نیستم؛ چراکه اگر بدنش را با قیچی قطعه‌قطعه کنند، برای او خیر است و اگر پادشاهی و سلطنت همه‌ی شرق و غرب زمین را به او بدهند، باز هم خیر او در آن است. به‌طور کلی، هرآنچه خداوند در حقّ او انجام دهد، برای او خیر خواهد بود. به من بگویید: «شما کجا و سلیمان‌بن‌داود (علیه السلام) کجا»؟ یوسف (علیه السلام) به عزیز مصر گفت: مرا سرپرست خزائن سرزمین (مصر) قرار ده، که نگهدارنده و آگاهم!. (

یوسف/۵۵

) پس به آنچه که خواست، دست یافت و قدرت پادشاه مصر و سرزمین‌های اطراف آن تا یمن را از آن خود کرد. مردمان این سرزمین‌ها برای دستیابی به آذوقه، نزد او می‌آمدند و به خاطر قحطی که به آن دچار شده بودند، غذایشان را تأمین می‌کردند. یوسف (علیه السلام) نیز حق می‌گفت و به آن عمل می‌کرد. امّا سراغ نداریم، کسی یوسف (علیه السلام) را به خاطر چنین امکاناتی بازخواست کرده باشد.

منظور از مشرکین در آیه وَ ویْل للمُشْرِکِینَ (

فصلت/۶

) کسانی هستند که به اسلام اقرار و اعتراف کرده‌اند اما در اعمالشان مرتکب شرک می‌شوند. این همان امری است که خداوند در آیه زیر بیان نموده و فرموده است: ومَا یُؤْمِنُ أَکْثَرُهُمْ بِاللهِ إِلاَّ وهُم مُّشْرِکُونَ یعنی آنها به وسیله اعمالشان مرتکب شرک می‌شوند. هرگاه به آنها دستور انجام کاری داده شود، بر خلاف فرموده خداوند عمل می‌کنند. به همین دلیل خداوند آنها را مشرک نامیده است.

در قرآن مجید از شرک هم در چهار موضوع گفتگو شده است ... وجه دوّم از شرک، شرک اعمال است، خداوند می‌فرماید: وَ ما یُؤْمِنُ أَکْثَرُهُمْ بِالله إِلَّا وَ هُمْ مُشْرِکُونَ، در جای دیگری فرموده است: [آن‌ها] دانشمندان و راهبان خویش را معبودهایی در برابر خدا قرار دادند. (

توبه/۳۱

) البتّه معلوم است که آن‌ها برای رهبران دینی خود روزه نگرفتند و برای آنان نماز هم نگذاردند، ولی هرچه آن‌ها گفتند مردم از آن‌ها اطاعت کردند، حلال‌ها را برای آن‌ها حرام نمودند، و حرام‌ها را حلال ساختند، مردم در نتیجه آن‌ها را پرستیدند درحالی‌که نمی‌دانستند آن‌ها را می‌پرستندو به من می‌گویند: شرک در اعمال و طاعات.

برای او (خدا) نام‌های نیکی است، دیگران به آن نام‌ها نامگذاری نمی‌شوند و خداوند در قرآن به‌همین موضوع اشاره کرده است: بدان نام‌هایش بخوانید. آن‌ها را که به نام‌های خدا الحاد می‌ورزند واگذارید. (

اعراف/۱۸۰

). اگر از روی جهالت و نادانی چنین کنند. پس هر آن‌کس که از روی نادانی در باب اسامی پروردگار متعال، دچار الحاد شود، بی‌آنکه بداند، شرک ورزیده است و به خداوند، کافر شده است، درحالی‌که فکر می‌کند، کار خوبی انجام می‌دهد. از همین‌رو است که خداوند فرموده است: وَمَا یُؤْمِنُ أَکْثَرُهُمْ بِالله إِلاَّ وَ هُم مُّشْرِکُونَ پس همین جماعت هستند که از روی جهالت در اسامی خداوند به الحاد دچار می‌شوند و این اسامی را در آنجا که شایسته نیست، می‌نهند.

خداوند عزّوجلّ فرموده است: باید از میان شما، جمعی دعوت به نیکی، و امر به معروف و نهی از منکر کنند! و آن‌ها همان رستگارانند. (

آل‌عمران/۱۰۴

) آنگاه این گروه را معرفی فرموده، اینکه آن‌ها از میان چه کسانی و از نسل ابراهیم و اسماعیل (علیها السلام) هستند، کسانی که از ساکنین مکّه بوده و هیچ‌گاه جز خداوند را پرستش نکرده‌اند، کسانی که اهل مسجدالحرام بوده و دعوت ابراهیم و اسماعیل (علیها السلام) شامل آن‌ها گردیده است؛ آن‌ها که خداوند در قرآن خبر داده پلیدی و گناه را از ای-شان دور و کام-لاً آن‌ها را پاک فرموده است؛ کسانی که قبل از این در بیان ویژگی امّت ابراهیم (علیه السلام) آن‌ها را توصیف نمودیم؛ همان‌ها که خداوند در آیه: أَدْعُوا إِلَی الله عَلی بَصِیرَةٍ أَنَا وَ مَنِ اتَّبَعَنِی ایشان را اراده فرموده است، یعنی اوّلین کسانی که پیش از دیگر مخلوقات، از پیامبر اسلام (صلی الله علیه و آله) در ایمان‌آوردن به او و تصدیق‌کردن او در آنچه از جانب خداوند عزّوجلّ آورده، پیروی کردند؛ از میان امّتی که پیامبر اسلام (صلی الله علیه و آله) در میان آن‌ها و از میان آن‌ها و به‌سوی آن‌ها برانگیخته شده است؛ کسانی که هیچگاه به خداوند شرک نورزیده و ایمانشان را با ستمِ شرک درنیامیختند.

در کتاب عیون‌الأخبار در بخشی از روایت مفصلی که از امام رضا (علیه السلام) در مورد هاروت و ماروت [نام دو فرشته که بر مردم بابل نازل شدند] ذیل آیه: و [یهود] از آنچه شیاطین در عصر سلیمان بر مردم می‌خواندند پیروی کردند. سلیمان هرگز [دست به سحر نیالود و] کافر نشد. (

بقره/۱۰۲

). رسیده، چنین آمده است: «آیا نمی‌دانی که خداوند عزّوجلّ هرگز دنیا را از پیغمبر یا امامی از جنس بشر، خالی نگذاشته است؟ آیا خداوند نفرموده است و إِلاَّ رِجالاً نُوحی إِلَیْهِمْ مِنْ أَهْلِ الْقُری خداوند خود خبر داده است که فرشتگان را به‌عنوان امامان و حاکمان به زمین نفرستاده است بلکه آنان فقط به‌سوی پیامبران خدا [برای ابلاغ وحی] فرستاده شده‌اند».
